+//! GGUF Tokenizer - Extract vocabulary from GGUF and use metal0 BPE tokenizer
+//!
+//! This module extracts vocabulary from GGUF files and uses metal0's optimized
+//! BPE tokenizer directly. No JSON file needed - works with any GGUF model.
+
+const std = @import("std");
+const metal0_tokenizer = @import("tokenizer");
+const log = std.log.scoped(.gguf_tokenizer);
+
+/// GGUF Tokenizer - uses metal0's BPE tokenizer with vocab from GGUF
+pub const GGUFTokenizer = struct {
+    allocator: std.mem.Allocator,
+    tokenizer: metal0_tokenizer.Tokenizer,
+
+    // Special tokens
+    bos_token_id: u32 = 1,
+    eos_token_id: u32 = 2,
+
+    const Self = @This();
+
+    /// Initialize from GGUF file path - extracts vocab and builds metal0 tokenizer
+    pub fn init(allocator: std.mem.Allocator, gguf_path: []const u8) !Self {
+        log.info("Loading tokenizer from GGUF: {s}", .{std.fs.path.basename(gguf_path)});
+
+        const file = try std.fs.cwd().openFile(gguf_path, .{});
+        defer file.close();
+
+        const stat = try file.stat();
+        const mmap_ptr = try std.posix.mmap(
+            null,
+            stat.size,
+            std.posix.PROT.READ,
+            .{ .TYPE = .PRIVATE },
+            file.handle,
+            0,
+        );
+        defer std.posix.munmap(mmap_ptr);
+
+        const data = mmap_ptr[0..stat.size];
+
+        // Parse GGUF header
+        var cursor: usize = 0;
+
+        // Magic (4 bytes)
+        const magic = std.mem.readInt(u32, data[cursor..][0..4], .little);
+        if (magic != 0x46554747) return error.InvalidGGUFMagic;
+        cursor += 4;
+
+        // Version (4 bytes)
+        const version = std.mem.readInt(u32, data[cursor..][0..4], .little);
+        if (version < 2 or version > 3) return error.UnsupportedGGUFVersion;
+        cursor += 4;
+
+        // Tensor count (8 bytes)
+        cursor += 8;
+
+        // Metadata KV count (8 bytes)
+        const kv_count = std.mem.readInt(u64, data[cursor..][0..8], .little);
+        cursor += 8;
+
+        log.info("GGUF v{}, {} metadata entries", .{ version, kv_count });
+
+        // Parse metadata to find tokenizer vocab
+        var vocab_tokens: ?[][]const u8 = null;
+        var bos_id: u32 = 1;
+        var eos_id: u32 = 2;
+
+        for (0..kv_count) |_| {
+            const key = readString(data, &cursor);
+            const value_type: u32 = std.mem.readInt(u32, data[cursor..][0..4], .little);
+            cursor += 4;
+
+            if (std.mem.eql(u8, key, "tokenizer.ggml.tokens")) {
+                if (value_type != 9) {
+                    skipValue(data, &cursor, value_type);
+                    continue;
+                }
+                const arr_type = std.mem.readInt(u32, data[cursor..][0..4], .little);
+                cursor += 4;
+                const arr_len = std.mem.readInt(u64, data[cursor..][0..8], .little);
+                cursor += 8;
+
+                if (arr_type != 8) {
+                    for (0..arr_len) |_| skipValue(data, &cursor, arr_type);
+                    continue;
+                }
+
+                var tokens = try allocator.alloc([]const u8, arr_len);
+                for (0..arr_len) |i| {
+                    const token_str = readString(data, &cursor);
+                    tokens[i] = token_str; // Don't dupe - metal0 will dupe
+                }
+                vocab_tokens = tokens;
+                log.info("Loaded {} vocabulary tokens from GGUF", .{arr_len});
+            } else if (std.mem.eql(u8, key, "tokenizer.ggml.bos_token_id")) {
+                bos_id = readU32Value(data, &cursor, value_type);
+            } else if (std.mem.eql(u8, key, "tokenizer.ggml.eos_token_id")) {
+                eos_id = readU32Value(data, &cursor, value_type);
+            } else {
+                skipValue(data, &cursor, value_type);
+            }
+        }
+
+        const vocab = vocab_tokens orelse return error.NoVocabInGGUF;
+        defer allocator.free(vocab);
+
+        // Initialize metal0 tokenizer directly from vocab
+        log.info("Building metal0 BPE tokenizer from GGUF vocab...", .{});
+        const tokenizer = try metal0_tokenizer.Tokenizer.initFromVocab(vocab, allocator);
+
+        log.info("Tokenizer ready: vocab_size={}, bos={}, eos={}", .{ vocab.len, bos_id, eos_id });
+
+        return Self{
+            .allocator = allocator,
+            .tokenizer = tokenizer,
+            .bos_token_id = bos_id,
+            .eos_token_id = eos_id,
+        };
+    }
+
+    pub fn deinit(self: *Self) void {
+        self.tokenizer.deinit();
+    }
+
+    /// Encode text to token IDs using metal0 BPE tokenizer
+    pub fn encode(self: *Self, text: []const u8, add_bos: bool) ![]u32 {
+        // Get arena-allocated result first
+        const arena_encoded = try self.tokenizer.encode(text);
+
+        if (add_bos) {
+            // Allocate result with bos token prepended
+            var result = try self.allocator.alloc(u32, arena_encoded.len + 1);
+            result[0] = self.bos_token_id;
+            @memcpy(result[1..], arena_encoded);
+            // Don't free arena_encoded - it's arena memory, gets freed on next encode()
+            return result;
+        }
+
+        // Copy to caller-owned memory
+        return try self.allocator.dupe(u32, arena_encoded);
+    }
+
+    /// Decode token IDs to text using metal0 tokenizer
+    pub fn decode(self: *Self, tokens: []const u32) ![]u8 {
+        return try self.tokenizer.decode(tokens);
+    }
+
+    /// Decode single token to text
+    pub fn decodeToken(self: *Self, token_id: u32) ?[]const u8 {
+        return self.tokenizer.vocab_r.get(token_id);
+    }
+};
+
+// Helper functions for reading GGUF
+
+fn readString(data: []const u8, cursor: *usize) []const u8 {
+    const len = std.mem.readInt(u64, data[cursor.*..][0..8], .little);
+    cursor.* += 8;
+    const str = data[cursor.*..][0..len];
+    cursor.* += len;
+    return str;
+}
+
+fn readU32Value(data: []const u8, cursor: *usize, value_type: u32) u32 {
+    return switch (value_type) {
+        4, 5 => blk: {
+            const val = std.mem.readInt(u32, data[cursor.*..][0..4], .little);
+            cursor.* += 4;
+            break :blk val;
+        },
+        10, 11 => blk: {
+            const val = std.mem.readInt(u64, data[cursor.*..][0..8], .little);
+            cursor.* += 8;
+            break :blk @truncate(val);
+        },
+        else => blk: {
+            skipValue(data, cursor, value_type);
+            break :blk 0;
+        },
+    };
+}
+
+fn skipValue(data: []const u8, cursor: *usize, value_type: u32) void {
+    switch (value_type) {
+        0, 1, 7 => cursor.* += 1,
+        2, 3 => cursor.* += 2,
+        4, 5, 6 => cursor.* += 4,
+        10, 11, 12 => cursor.* += 8,
+        8 => {
+            const len = std.mem.readInt(u64, data[cursor.*..][0..8], .little);
+            cursor.* += 8 + len;
+        },
+        9 => {
+            const arr_type = std.mem.readInt(u32, data[cursor.*..][0..4], .little);
+            cursor.* += 4;
+            const arr_len = std.mem.readInt(u64, data[cursor.*..][0..8], .little);
+            cursor.* += 8;
+            for (0..arr_len) |_| {
+                skipValue(data, cursor, arr_type);
+            }
+        },
+        else => {},
+    }
+}

