+    const config_dir = try std.fmt.allocPrint(allocator, "{s}/.zell/models", .{home});
+    defer allocator.free(config_dir);
+
+    std.fs.cwd().makePath(config_dir) catch {};
+
+    // Write model config JSON
+    const config_path = try std.fmt.allocPrint(allocator, "{s}/{s}.json", .{ config_dir, name });
+    defer allocator.free(config_path);
+
+    var config_file = try std.fs.cwd().createFile(config_path, .{});
+    defer config_file.close();
+
+    // Build JSON content
+    const draft_str = if (draft_model) |d|
+        try std.fmt.allocPrint(allocator, "\"{s}\"", .{d})
+    else
+        try allocator.dupe(u8, "null");
+    defer allocator.free(draft_str);
+
+    const json_content = try std.fmt.allocPrint(allocator,
+        \\{{
+        \\  "model_path": "{s}",
+        \\  "draft_model": {s},
+        \\  "created": {d}
+        \\}}
