+    // Get path to current zell binary
+    const exe_path = try std.fs.selfExePathAlloc(allocator);
+    defer allocator.free(exe_path);
+
+    // Create symlink in current directory
+    const symlink_path = try std.fmt.allocPrint(allocator, "./{s}", .{name});
+    defer allocator.free(symlink_path);
+
+    // Remove existing symlink if present
+    std.fs.cwd().deleteFile(symlink_path) catch {};
+
+    // Create symlink to zell
+    std.fs.cwd().symLink(exe_path, symlink_path, .{}) catch |err| {
+        std.debug.print("Warning: Could not create symlink: {}\n", .{err});
