+/// Load model config for standalone executable mode
+/// Returns (model_path, draft_model) or null if not a standalone invocation
+fn loadStandaloneConfig(allocator: std.mem.Allocator, exe_name: []const u8) !?struct { model_path: []const u8, draft_model: ?[]const u8 } {
+    const home = std.posix.getenv("HOME") orelse return null;
+
+    const config_path = try std.fmt.allocPrint(allocator, "{s}/.zell/models/{s}.json", .{ home, exe_name });
+    defer allocator.free(config_path);
+
+    const config_file = std.fs.cwd().openFile(config_path, .{}) catch return null;
+    defer config_file.close();
+
+    const content = try config_file.readToEndAlloc(allocator, 1024 * 1024);
+    defer allocator.free(content);
+
+    const parsed = std.json.parseFromSlice(struct {
+        model_path: []const u8,
+        draft_model: ?[]const u8 = null,
+    }, allocator, content, .{ .ignore_unknown_fields = true }) catch return null;
+
+    // Dupe the strings since parsed will be freed
+    const model_path = try allocator.dupe(u8, parsed.value.model_path);
