+//! Two-Tier Mixtral Inference Engine (Option B-Lite)
+//!
+//! Architecture:
+//! TIER 1 - RESIDENT (GPU VRAM): Attention weights + norms (~2.6GB Q4_K)
+//!   - Uploaded to GPU at init time, stays resident
+//!   - Q/K/V/O projections run on Metal GPU (~10ms/layer vs ~13s CPU)
+//!
+//! TIER 2 - STREAMING (SSD): MoE expert weights (~40GB)
+//!   - Zero-copy mmap pointers passed to Metal GPU
+//!   - Loaded on demand per layer (~50ms/layer)
+//!
+//! Result: 442s → ~0.3s attention, targeting 10+ tok/s
+
+const std = @import("std");
+const gguf = @import("inference/gguf_loader.zig");
+const moe_metal = @import("moe_metal.zig");
+const objc = @import("inference/metal/objc.zig");
+
+const log = std.log.scoped(.mixtral_lazy);
+
+/// Mixtral model configuration
+pub const MixtralConfig = struct {
+    n_vocab: u32 = 32000,
+    n_ctx: u32 = 4096,
+    n_embd: u32 = 4096,
+    n_head: u32 = 32,
+    n_head_kv: u32 = 8,
+    n_layer: u32 = 32,
+    n_ff: u32 = 14336,
+    n_expert: u32 = 8,
+    n_expert_used: u32 = 2,
+    rope_theta: f32 = 1000000.0,
+    rms_norm_eps: f32 = 1e-5,
+};
+
+/// Lazy tensor - stores offset, loads on demand
+const LazyTensor = struct {
+    name: []const u8,
+    data: ?[]f32 = null,
+    is_loaded: bool = false,
+};
+
+/// KV Cache for attention
+pub const KVCache = struct {
+    allocator: std.mem.Allocator,
+    k_cache: [][]f32,
+    v_cache: [][]f32,
+    seq_len: u32,
+    n_ctx: u32,
+    head_dim: u32,
+    n_head_kv: u32,
+    n_layer: u32,
+
+    pub fn init(allocator: std.mem.Allocator, config: MixtralConfig) !*KVCache {
+        const self = try allocator.create(KVCache);
+        errdefer allocator.destroy(self);
+
+        const head_dim = config.n_embd / config.n_head;
+        const cache_size = config.n_head_kv * config.n_ctx * head_dim;
+
+        self.k_cache = try allocator.alloc([]f32, config.n_layer);
+        self.v_cache = try allocator.alloc([]f32, config.n_layer);
+
+        for (0..config.n_layer) |i| {
+            self.k_cache[i] = try allocator.alloc(f32, cache_size);
+            @memset(self.k_cache[i], 0);
+            self.v_cache[i] = try allocator.alloc(f32, cache_size);
+            @memset(self.v_cache[i], 0);
+        }
+
+        self.allocator = allocator;
+        self.seq_len = 0;
+        self.n_ctx = config.n_ctx;
+        self.head_dim = head_dim;
+        self.n_head_kv = config.n_head_kv;
+        self.n_layer = config.n_layer;
+
+        return self;
+    }
+
+    pub fn deinit(self: *KVCache) void {
+        for (self.k_cache) |k| self.allocator.free(k);
+        for (self.v_cache) |v| self.allocator.free(v);
+        self.allocator.free(self.k_cache);
+        self.allocator.free(self.v_cache);
+        self.allocator.destroy(self);
+    }
+
+    pub fn clear(self: *KVCache) void {
+        self.seq_len = 0;
+        for (self.k_cache) |k| @memset(k, 0);
+        for (self.v_cache) |v| @memset(v, 0);
+    }
+};
+
+/// Attention norm weights for one layer (F32, small - keep in RAM)
+const LayerNorms = struct {
+    attn_norm: ?[]f32 = null,
+    ffn_norm: ?[]f32 = null,
+    loaded: bool = false,
+};
+
+/// MoE expert pointers (zero-copy from mmap)
+const MoELayerPointers = struct {
+    router: ?[]const u8 = null,
+    gate: [8]?[]const u8 = [_]?[]const u8{null} ** 8,
+    up: [8]?[]const u8 = [_]?[]const u8{null} ** 8,
+    down: [8]?[]const u8 = [_]?[]const u8{null} ** 8,
+    is_loaded: bool = false,
+};
+
+/// Two-Tier Mixtral inference engine
+pub const MixtralLazyEngine = struct {
+    allocator: std.mem.Allocator,
+    config: MixtralConfig,
+
+    // GGUF loader (holds mmap'd file)
+    loader: *gguf.GGUFLoader,
+
+    // Metal MoE engine (handles BOTH resident attention AND streaming MoE)
+    moe_engine: *moe_metal.MetalMoEEngine,
+
+    // TIER 1: RESIDENT - Token embeddings (loaded on first use)
+    token_embeddings: ?[]f32 = null,
+    token_embeddings_loaded: bool = false,
+
+    // TIER 1: RESIDENT - Output weights
+    output_norm: ?[]f32 = null,
+    output_weight: ?[]f32 = null,
+    output_loaded: bool = false,
+
+    // TIER 1: RESIDENT - Layer norms (F32, ~16KB/layer - in RAM)
+    layer_norms: []LayerNorms,
+
+    // TIER 1: RESIDENT - Attention Q/K/V/O weights are in GPU VRAM
+    // (Uploaded at init, accessed via moe_engine.resident_attn_weights)
+    resident_attention_loaded: bool = false,
+
+    // TIER 2: STREAMING - MoE expert pointers (zero-copy from mmap)
+    moe_pointers: []MoELayerPointers,
+
+    // Working buffers (always allocated - small)
+    hidden_state: []f32,
+    residual: []f32,
+    attn_out: []f32,
+    q: []f32,
+    k: []f32,
+    v: []f32,
+    logits: []f32,
+
+    // KV cache
+    kv_cache: *KVCache,
+
+    // CPU fallback: Pre-loaded F32 attention weights (loaded lazily)
+    layer_weights_f32: ?[]LayerWeightsF32 = null,
+
+    const Self = @This();
+
+    /// F32 attention weights for CPU fallback path
+    const LayerWeightsF32 = struct {
+        q_proj: []f32,
+        k_proj: []f32,
+        v_proj: []f32,
+        o_proj: []f32,
+    };
+
+    pub fn init(
+        allocator: std.mem.Allocator,
+        loader: *gguf.GGUFLoader,
+        moe_engine: *moe_metal.MetalMoEEngine,
+    ) !*Self {
+        const self = try allocator.create(Self);
+        errdefer allocator.destroy(self);
+
+        self.allocator = allocator;
+        self.loader = loader;
+        self.moe_engine = moe_engine;
+
+        // Extract config from GGUF metadata
+        self.config = MixtralConfig{
+            .n_vocab = loader.metadata.vocab_size,
+            .n_embd = loader.metadata.hidden_size,
+            .n_layer = loader.metadata.n_layers,
+            .n_head = loader.metadata.n_heads,
+            .n_head_kv = loader.metadata.n_kv_heads,
+            .n_ctx = 4096,
+            .n_ff = 14336,
+            .n_expert = 8,
+            .n_expert_used = 2,
+        };
+
+        log.info("Initializing Two-Tier Mixtral engine", .{});
+        log.info("  TIER 1 (RESIDENT): Attention Q/K/V/O → GPU VRAM", .{});
+        log.info("  TIER 2 (STREAMING): MoE experts → SSD on demand", .{});
+        log.info("  Vocab: {}, Embd: {}, Layers: {}", .{
+            self.config.n_vocab,
+            self.config.n_embd,
+            self.config.n_layer,
+        });
+
+        const n_embd = self.config.n_embd;
+        const n_vocab = self.config.n_vocab;
+        const head_dim = n_embd / self.config.n_head;
+
+        // Allocate ONLY working buffers (small - ~100KB total)
+        self.hidden_state = try allocator.alloc(f32, n_embd);
+        self.residual = try allocator.alloc(f32, n_embd);
+        self.attn_out = try allocator.alloc(f32, n_embd);
+        self.q = try allocator.alloc(f32, self.config.n_head * head_dim);
+        self.k = try allocator.alloc(f32, self.config.n_head_kv * head_dim);
+        self.v = try allocator.alloc(f32, self.config.n_head_kv * head_dim);
+        self.logits = try allocator.alloc(f32, n_vocab);
+
+        // Initialize KV cache
+        self.kv_cache = try KVCache.init(allocator, self.config);
+
+        // Initialize layer norms (small F32 arrays, loaded lazily)
+        self.layer_norms = try allocator.alloc(LayerNorms, self.config.n_layer);
+        for (0..self.config.n_layer) |i| {
+            self.layer_norms[i] = LayerNorms{};
+        }
+
+        // Initialize MoE pointers (will be filled lazily from mmap)
+        self.moe_pointers = try allocator.alloc(MoELayerPointers, self.config.n_layer);
+        for (0..self.config.n_layer) |i| {
+            self.moe_pointers[i] = MoELayerPointers{};
+        }
+
+        // Initialize lazy fields
+        self.token_embeddings = null;
+        self.token_embeddings_loaded = false;
+        self.output_norm = null;
+        self.output_weight = null;
+        self.output_loaded = false;
+        self.resident_attention_loaded = false;
+        self.layer_weights_f32 = null;
+
+        log.info("Two-Tier engine initialized", .{});
+        log.info("Call uploadResidentAttention() to upload attention to GPU VRAM", .{});
+
+        return self;
+    }
+
+    pub fn deinit(self: *Self) void {
+        // Free layer norms
+        for (self.layer_norms) |ln| {
+            if (ln.attn_norm) |d| self.allocator.free(d);
+            if (ln.ffn_norm) |d| self.allocator.free(d);
+        }
+        self.allocator.free(self.layer_norms);
+        self.allocator.free(self.moe_pointers);
+
+        // Free loaded embeddings/output
+        if (self.token_embeddings) |e| self.allocator.free(e);
+        if (self.output_norm) |n| self.allocator.free(n);
+        if (self.output_weight) |w| self.allocator.free(w);
+
+        // Free working buffers
+        self.allocator.free(self.hidden_state);
+        self.allocator.free(self.residual);
+        self.allocator.free(self.attn_out);
+        self.allocator.free(self.q);
+        self.allocator.free(self.k);
+        self.allocator.free(self.v);
+        self.allocator.free(self.logits);
+
+        self.kv_cache.deinit();
+        self.allocator.destroy(self);
+    }
+
+    /// Ensure token embeddings are loaded
+    pub fn ensureEmbeddingsLoaded(self: *Self) !void {
+        if (self.token_embeddings_loaded) return;
+
+        log.info("Loading token embeddings on first use...", .{});
+        const n_vocab = self.config.n_vocab;
+        const n_embd = self.config.n_embd;
+
+        self.token_embeddings = try self.allocator.alloc(f32, n_vocab * n_embd);
+        try self.loader.dequantizeToF32("token_embd.weight", self.token_embeddings.?);
+        self.token_embeddings_loaded = true;
+        log.info("Token embeddings loaded ({} MB)", .{(n_vocab * n_embd * 4) / (1024 * 1024)});
+    }
+
+    /// Ensure output weights are loaded
+    fn ensureOutputLoaded(self: *Self) !void {
+        if (self.output_loaded) return;
+
+        log.info("Loading output weights on first use...", .{});
+        const n_vocab = self.config.n_vocab;
+        const n_embd = self.config.n_embd;
+
+        self.output_norm = try self.allocator.alloc(f32, n_embd);
+        if (self.loader.getTensor("output_norm.weight")) |tensor_info| {
+            log.info("Found output_norm.weight tensor: type={s}, elements={}", .{ @tagName(tensor_info.type_), tensor_info.numElements() });
+            try self.loader.dequantizeToF32("output_norm.weight", self.output_norm.?);
+        } else {
+            log.err("output_norm.weight not found in GGUF!", .{});
+            return error.OutputNormNotFound;
+        }
+
+        self.output_weight = try self.allocator.alloc(f32, n_vocab * n_embd);
+
+        // Try output.weight first (Mixtral standard)
+        if (self.loader.getTensor("output.weight")) |tensor_info| {
+            log.info("Found output.weight tensor: type={s}, elements={}", .{ @tagName(tensor_info.type_), tensor_info.numElements() });
+            try self.loader.dequantizeToF32("output.weight", self.output_weight.?);
+        } else if (self.loader.getTensor("lm_head.weight")) |tensor_info| {
+            log.info("Found lm_head.weight tensor: type={s}, elements={}", .{ @tagName(tensor_info.type_), tensor_info.numElements() });
+            try self.loader.dequantizeToF32("lm_head.weight", self.output_weight.?);
+        } else {
+            log.err("Neither output.weight nor lm_head.weight found in GGUF!", .{});
+            return error.OutputWeightNotFound;
+        }
+
+        self.output_loaded = true;
+        log.info("Output weights loaded ({} MB)", .{(n_vocab * n_embd * 4) / (1024 * 1024)});
+
+        // DEBUG: Print first 10 output_norm values
+        log.info("output_norm[0..10]: {any}", .{self.output_norm.?[0..10]});
+
+        // DEBUG: Print first 10 output_weight values (first row of projection matrix)
+        log.info("output_weight[0..10]: {any}", .{self.output_weight.?[0..10]});
+
+        // DEBUG: Check token 1823's output weights (row 1823 of the projection matrix)
+        const token_1823_offset = 1823 * n_embd;
+        log.info("output_weight[token 1823][0..10]: {any}", .{self.output_weight.?[token_1823_offset..][0..10]});
+
+        // DEBUG: Compare with a few other tokens
+        const token_2965_offset = 2965 * n_embd;  // Second most common from our test
+        log.info("output_weight[token 2965][0..10]: {any}", .{self.output_weight.?[token_2965_offset..][0..10]});
+
+        // DEBUG: Check for NaN or Inf
+        var has_nan = false;
+        var has_inf = false;
+        for (self.output_norm.?) |v| {
+            if (std.math.isNan(v)) has_nan = true;
+            if (std.math.isInf(v)) has_inf = true;
+        }
+        for (self.output_weight.?[0..1000]) |v| {
+            if (std.math.isNan(v)) has_nan = true;
+            if (std.math.isInf(v)) has_inf = true;
+        }
+        if (has_nan) log.err("WARNING: NaN detected in output weights!", .{});
+        if (has_inf) log.err("WARNING: Inf detected in output weights!", .{});
+    }
+
+    /// Upload ALL attention weights to GPU VRAM (TIER 1: RESIDENT)
+    /// Call this once at startup - takes ~10s but enables fast inference
+    pub fn uploadResidentAttention(self: *Self) !void {
+        if (self.resident_attention_loaded) return;
+
+        log.info("Uploading attention weights to GPU VRAM (TIER 1: RESIDENT)...", .{});
+        log.info("  This is a one-time cost (~10s) for ~2.6GB upload", .{});
+
+        var name_buf: [64]u8 = undefined;
+        var total_bytes: usize = 0;
+
+        for (0..self.config.n_layer) |layer_idx| {
+            // Get raw Q4_K tensor data from mmap (zero-copy pointers)
+            // Note: Must lookup each tensor immediately after formatting name (buffer reuse)
+            var name = try std.fmt.bufPrint(&name_buf, "blk.{}.attn_q.weight", .{layer_idx});
+            const attn_q = self.loader.getTensorDataByName(name) orelse return error.TensorNotFound;
+
+            name = try std.fmt.bufPrint(&name_buf, "blk.{}.attn_k.weight", .{layer_idx});
+            const attn_k = self.loader.getTensorDataByName(name) orelse return error.TensorNotFound;
+
+            name = try std.fmt.bufPrint(&name_buf, "blk.{}.attn_v.weight", .{layer_idx});
+            const attn_v = self.loader.getTensorDataByName(name) orelse return error.TensorNotFound;
+
+            // DEBUG: Check Q8_0 scale values for K vs V (layer 0 only)
+            if (layer_idx == 0) {
+                // Q8_0: 34 bytes per block (2-byte f16 scale + 32 int8 values)
+                const Q8_BLOCK_BYTES = 34;
+                log.info("=== Q8_0 WEIGHT SCALE DEBUG (layer 0) ===", .{});
+                log.info("  K weights size: {} bytes, V weights size: {} bytes", .{ attn_k.len, attn_v.len });
+                log.info("  K ptr: {*}, V ptr: {*}", .{ attn_k.ptr, attn_v.ptr });
+
+                var k_scale_sum: f32 = 0.0;
+                var v_scale_sum: f32 = 0.0;
+                var k_qs_sum: i64 = 0;
+                var v_qs_sum: i64 = 0;
+                const num_blocks = @min(100, attn_k.len / Q8_BLOCK_BYTES);
+
+                for (0..num_blocks) |block_idx| {
+                    const offset = block_idx * Q8_BLOCK_BYTES;
+                    const k_scale_bytes: *const [2]u8 = @ptrCast(attn_k[offset..][0..2]);
+                    const v_scale_bytes: *const [2]u8 = @ptrCast(attn_v[offset..][0..2]);
+
+                    // Interpret as f16 and convert to f32
+                    const k_scale_u16 = @as(u16, k_scale_bytes[0]) | (@as(u16, k_scale_bytes[1]) << 8);
+                    const v_scale_u16 = @as(u16, v_scale_bytes[0]) | (@as(u16, v_scale_bytes[1]) << 8);
+
+                    // Convert f16 to f32 properly
+                    const k_scale: f32 = @floatCast(@as(f16, @bitCast(k_scale_u16)));
+                    const v_scale: f32 = @floatCast(@as(f16, @bitCast(v_scale_u16)));
+
+                    k_scale_sum += @abs(k_scale);
+                    v_scale_sum += @abs(v_scale);
+
+                    // Also sum the int8 quantized values
+                    const k_qs = attn_k[offset + 2 .. offset + 34];
+                    const v_qs = attn_v[offset + 2 .. offset + 34];
+                    for (0..32) |i| {
+                        k_qs_sum += @as(i64, @abs(@as(i8, @bitCast(k_qs[i]))));
+                        v_qs_sum += @as(i64, @abs(@as(i8, @bitCast(v_qs[i]))));
+                    }
+                }
+
+                const k_avg = k_scale_sum / @as(f32, @floatFromInt(num_blocks));
+                const v_avg = v_scale_sum / @as(f32, @floatFromInt(num_blocks));
+                const total_qs: f32 = @floatFromInt(num_blocks);
+                const k_qs_avg = @as(f32, @floatFromInt(k_qs_sum)) / (total_qs * 32.0);
+                const v_qs_avg = @as(f32, @floatFromInt(v_qs_sum)) / (total_qs * 32.0);
+                log.info("  K avg scale (first {} blocks): {d:.6}", .{ num_blocks, k_avg });
+                log.info("  V avg scale (first {} blocks): {d:.6}", .{ num_blocks, v_avg });
+                log.info("  K avg |qs| (first {} blocks): {d:.2}", .{ num_blocks, k_qs_avg });
+                log.info("  V avg |qs| (first {} blocks): {d:.2}", .{ num_blocks, v_qs_avg });
+
+                // Estimated dequantized magnitude: scale * avg(|qs|)
+                log.info("  K estimated magnitude: {d:.6}", .{k_avg * k_qs_avg});
+                log.info("  V estimated magnitude: {d:.6}", .{v_avg * v_qs_avg});
+
+                if (v_avg < k_avg * 0.1) {
+                    log.warn("  ⚠️  V scales are 10x+ smaller than K! V weights may be corrupted!", .{});
+                }
+
+                // Verify K and V buffers on GPU match source data
+                log.info("  Source K first bytes: {x:0>2} {x:0>2} {x:0>2} {x:0>2}", .{ attn_k[0], attn_k[1], attn_k[2], attn_k[3] });
+                log.info("  Source V first bytes: {x:0>2} {x:0>2} {x:0>2} {x:0>2}", .{ attn_v[0], attn_v[1], attn_v[2], attn_v[3] });
+
+                // Check tensor types and dimensions
+                const k_name_for_type = try std.fmt.bufPrint(&name_buf, "blk.{}.attn_k.weight", .{layer_idx});
+                if (self.loader.getTensor(k_name_for_type)) |k_info| {
+                    log.info("  K tensor type: {}, dims: {}x{}", .{ k_info.type_, k_info.dimensions[0], k_info.dimensions[1] });
+                    // Q8_0 expected size: n_out * ceil(n_in/32) * 34 bytes
+                    const k_expected_bytes = k_info.dimensions[0] * ((k_info.dimensions[1] + 31) / 32) * 34;
+                    log.info("  K expected bytes: {}, actual: {}", .{ k_expected_bytes, attn_k.len });
+                }
+                const v_name_for_type = try std.fmt.bufPrint(&name_buf, "blk.{}.attn_v.weight", .{layer_idx});
+                if (self.loader.getTensor(v_name_for_type)) |v_info| {
+                    log.info("  V tensor type: {}, dims: {}x{}", .{ v_info.type_, v_info.dimensions[0], v_info.dimensions[1] });
+                    // Q8_0 expected size: n_out * ceil(n_in/32) * 34 bytes
+                    const v_expected_bytes = v_info.dimensions[0] * ((v_info.dimensions[1] + 31) / 32) * 34;
+                    log.info("  V expected bytes: {}, actual: {}", .{ v_expected_bytes, attn_v.len });
+                    if (v_expected_bytes != attn_v.len) {
+                        log.warn("  ⚠️  V buffer size mismatch! Expected {} but got {}", .{ v_expected_bytes, attn_v.len });
+                    }
+                }
+
+                // CPU verification: manually compute first output element of V projection
+                // V is [kv_dim, n_embd] = [1024, 4096], input is buf_normed [4096]
+                // V[0] = sum(V_weight[0,i] * input[i]) for i in 0..4096
+                const Q8_BLOCK = 34; // 2 bytes scale + 32 int8 values
+                const blocks_per_row = (4096 + 31) / 32; // = 128 blocks per row
+
+                var cpu_v0: f32 = 0.0;
+                var cpu_k0: f32 = 0.0;
+
+                // Get normed input that was used for projection
+                // (need to get it from mmap since we already used it)
+                // Actually let's just read first 128 blocks of row 0 for V weights
+                for (0..blocks_per_row) |blk_idx| {
+                    const v_blk_offset = blk_idx * Q8_BLOCK;
+                    const k_blk_offset = blk_idx * Q8_BLOCK;
+
+                    // V weight scale
+                    const v_scale_u16 = @as(u16, attn_v[v_blk_offset]) | (@as(u16, attn_v[v_blk_offset + 1]) << 8);
+                    const v_scale: f32 = @floatCast(@as(f16, @bitCast(v_scale_u16)));
+
+                    // K weight scale
+                    const k_scale_u16 = @as(u16, attn_k[k_blk_offset]) | (@as(u16, attn_k[k_blk_offset + 1]) << 8);
+                    const k_scale: f32 = @floatCast(@as(f16, @bitCast(k_scale_u16)));
+
+                    // Sum quantized values (just to verify they're non-zero)
+                    var v_qs_blk_sum: f32 = 0.0;
+                    var k_qs_blk_sum: f32 = 0.0;
+                    for (0..32) |qi| {
+                        const v_q: i8 = @bitCast(attn_v[v_blk_offset + 2 + qi]);
+                        const k_q: i8 = @bitCast(attn_k[k_blk_offset + 2 + qi]);
+                        v_qs_blk_sum += @as(f32, @floatFromInt(v_q)) * v_scale;
+                        k_qs_blk_sum += @as(f32, @floatFromInt(k_q)) * k_scale;
+                    }
+                    cpu_v0 += v_qs_blk_sum;
+                    cpu_k0 += k_qs_blk_sum;
+                }
+
+                log.info("  CPU manual check (sum of dequantized row 0):", .{});
+                log.info("    K row 0 sum (weights only): {d:.4}", .{cpu_k0});
+                log.info("    V row 0 sum (weights only): {d:.4}", .{cpu_v0});
+                log.info("    Ratio K/V: {d:.2}x", .{cpu_k0 / cpu_v0});
+
+                // This suggests V weights are NOT corrupted! The weights are similar in magnitude.
+                // The bug must be in how the GPU kernel processes them OR in buffer handling.
+                log.warn("  ⚠️  V weights seem OK - bug is likely in GPU kernel or buffer!", .{});
+            }
+
+            name = try std.fmt.bufPrint(&name_buf, "blk.{}.attn_output.weight", .{layer_idx});
+            const attn_o = self.loader.getTensorDataByName(name) orelse return error.TensorNotFound;
+
+            name = try std.fmt.bufPrint(&name_buf, "blk.{}.attn_norm.weight", .{layer_idx});
+            const attn_norm = self.loader.getTensorDataByName(name) orelse return error.TensorNotFound;
+
+            // DEBUG: Print attn_norm as F32 values
+            if (layer_idx == 0) {
+                const attn_norm_f32: []const f32 = @as([*]const f32, @ptrCast(@alignCast(attn_norm.ptr)))[0..4096];
+                log.info("=== ATTN NORM DEBUG (layer 0) ===", .{});
+                log.info("  First 10 values: {d:.6}, {d:.6}, {d:.6}, {d:.6}, {d:.6}, {d:.6}, {d:.6}, {d:.6}, {d:.6}, {d:.6}", .{
+                    attn_norm_f32[0], attn_norm_f32[1], attn_norm_f32[2], attn_norm_f32[3], attn_norm_f32[4],
+                    attn_norm_f32[5], attn_norm_f32[6], attn_norm_f32[7], attn_norm_f32[8], attn_norm_f32[9],
+                });
+                var sum: f32 = 0;
+                for (attn_norm_f32) |v| sum += v;
+                log.info("  Sum: {d:.6}, Mean: {d:.6}", .{ sum, sum / 4096.0 });
+            }
+
+            name = try std.fmt.bufPrint(&name_buf, "blk.{}.ffn_norm.weight", .{layer_idx});
+            const ffn_norm = self.loader.getTensorDataByName(name) orelse return error.TensorNotFound;
+
+            // Upload to GPU VRAM via MetalMoEEngine
+            try self.moe_engine.uploadLayerAttention(
+                @intCast(layer_idx),
+                attn_q,
+                attn_k,
+                attn_v,
+                attn_o,
+                attn_norm,
+                ffn_norm,
+            );
+
+            // VERIFY: Read back GPU buffer and compare with source (layer 0 only)
+            if (layer_idx == 0) {
+                const layer = self.moe_engine.resident_attn_weights[0];
+                const gpu_v_ptr: [*]const u8 = @ptrCast(objc.bufferContents(layer.attn_v.?));
+                const gpu_k_ptr: [*]const u8 = @ptrCast(objc.bufferContents(layer.attn_k.?));
+
+                log.info("=== GPU BUFFER VERIFICATION (layer 0) ===", .{});
+                log.info("  Source V first 8 bytes: {x:0>2} {x:0>2} {x:0>2} {x:0>2} {x:0>2} {x:0>2} {x:0>2} {x:0>2}", .{ attn_v[0], attn_v[1], attn_v[2], attn_v[3], attn_v[4], attn_v[5], attn_v[6], attn_v[7] });
+                log.info("  GPU V first 8 bytes:    {x:0>2} {x:0>2} {x:0>2} {x:0>2} {x:0>2} {x:0>2} {x:0>2} {x:0>2}", .{ gpu_v_ptr[0], gpu_v_ptr[1], gpu_v_ptr[2], gpu_v_ptr[3], gpu_v_ptr[4], gpu_v_ptr[5], gpu_v_ptr[6], gpu_v_ptr[7] });
+                log.info("  Source K first 8 bytes: {x:0>2} {x:0>2} {x:0>2} {x:0>2} {x:0>2} {x:0>2} {x:0>2} {x:0>2}", .{ attn_k[0], attn_k[1], attn_k[2], attn_k[3], attn_k[4], attn_k[5], attn_k[6], attn_k[7] });
+                log.info("  GPU K first 8 bytes:    {x:0>2} {x:0>2} {x:0>2} {x:0>2} {x:0>2} {x:0>2} {x:0>2} {x:0>2}", .{ gpu_k_ptr[0], gpu_k_ptr[1], gpu_k_ptr[2], gpu_k_ptr[3], gpu_k_ptr[4], gpu_k_ptr[5], gpu_k_ptr[6], gpu_k_ptr[7] });
+
+                // Check if GPU buffers match source
+                var k_match = true;
+                var v_match = true;
+                for (0..100) |i| {
+                    if (gpu_k_ptr[i] != attn_k[i]) k_match = false;
+                    if (gpu_v_ptr[i] != attn_v[i]) v_match = false;
+                }
+                log.info("  K buffer matches source (first 100 bytes): {}", .{k_match});
+                log.info("  V buffer matches source (first 100 bytes): {}", .{v_match});
+
+                if (!k_match or !v_match) {
+                    log.err("  ⚠️  GPU buffer doesn't match source! Upload is corrupted!", .{});
+                }
+            }
+
+            total_bytes += attn_q.len + attn_k.len + attn_v.len + attn_o.len;
+
+            if (layer_idx % 8 == 7) {
+                log.info("  Uploaded layers 0-{} ({} MB)", .{ layer_idx, total_bytes / (1024 * 1024) });
+            }
+        }
+
+        self.resident_attention_loaded = true;
+        self.moe_engine.resident_weights_loaded = true;
+
+        log.info("Attention weights uploaded to GPU VRAM ({} MB total)", .{total_bytes / (1024 * 1024)});
+        log.info("TIER 1 (RESIDENT) ready - attention runs on GPU now!", .{});
+    }
+
+    /// Load layer norms (small F32 arrays, ~32KB per layer)
+    pub fn ensureLayerNormsLoaded(self: *Self, layer_idx: usize) !void {
+        const ln = &self.layer_norms[layer_idx];
+        if (ln.loaded) return;
+
+        var name_buf: [64]u8 = undefined;
+        const n_embd = self.config.n_embd;
+
+        // Load attention norm
+        var name = try std.fmt.bufPrint(&name_buf, "blk.{}.attn_norm.weight", .{layer_idx});
+        ln.attn_norm = try self.allocator.alloc(f32, n_embd);
+        try self.loader.dequantizeToF32(name, ln.attn_norm.?);
+
+        // Load FFN norm
+        name = try std.fmt.bufPrint(&name_buf, "blk.{}.ffn_norm.weight", .{layer_idx});
+        ln.ffn_norm = try self.allocator.alloc(f32, n_embd);
+        try self.loader.dequantizeToF32(name, ln.ffn_norm.?);
+
+        ln.loaded = true;
+    }
+
+    /// Get MoE expert pointers (zero-copy from mmap)
+    fn ensureMoEPointersLoaded(self: *Self, layer_idx: usize) !void {
+        if (self.moe_pointers[layer_idx].is_loaded) return;
+
+        var name_buf: [64]u8 = undefined;
+        const mp = &self.moe_pointers[layer_idx];
+
+        // Router weights (F16, convert on GPU or use direct)
+        const router_name = try std.fmt.bufPrint(&name_buf, "blk.{}.ffn_gate_inp.weight", .{layer_idx});
+        mp.router = self.loader.getTensorDataByName(router_name);
+
+        // DEBUG: Check tensor types for layer 0
+        if (layer_idx == 0) {
+            if (self.loader.getTensor(router_name)) |info| {
+                log.info("DEBUG: {s} type = {}", .{ router_name, info.type_ });
+            }
+        }
+
+        // Expert weights - zero-copy pointers into mmap'd file
+        for (0..8) |e| {
+            const gate_name = try std.fmt.bufPrint(&name_buf, "blk.{}.ffn_gate.{}.weight", .{ layer_idx, e });
+            mp.gate[e] = self.loader.getTensorDataByName(gate_name);
+
+            // DEBUG: Check tensor types for layer 0, expert 0
+            if (layer_idx == 0 and e == 0) {
+                if (self.loader.getTensor(gate_name)) |info| {
+                    log.info("DEBUG: {s} type = {}", .{ gate_name, info.type_ });
+                }
+            }
+
+            const up_name = try std.fmt.bufPrint(&name_buf, "blk.{}.ffn_up.{}.weight", .{ layer_idx, e });
+            mp.up[e] = self.loader.getTensorDataByName(up_name);
+
+            if (layer_idx == 0 and e == 0) {
+                if (self.loader.getTensor(up_name)) |info| {
+                    log.info("DEBUG: {s} type = {}", .{ up_name, info.type_ });
+                }
+            }
+
+            const down_name = try std.fmt.bufPrint(&name_buf, "blk.{}.ffn_down.{}.weight", .{ layer_idx, e });
+            mp.down[e] = self.loader.getTensorDataByName(down_name);
+
+            if (layer_idx == 0 and e == 0) {
+                if (self.loader.getTensor(down_name)) |info| {
+                    log.info("DEBUG: {s} type = {}", .{ down_name, info.type_ });
+                }
+            }
+        }
+
+        mp.is_loaded = true;
+        log.debug("MoE pointers loaded for layer {} (zero-copy)", .{layer_idx});
+    }
+
+    /// RMSNorm
+    fn rmsNorm(self: *Self, input: []const f32, weight: []const f32, output: []f32) void {
+        var sum_sq: f32 = 0.0;
+        for (input) |x| sum_sq += x * x;
+        const rms = @sqrt(sum_sq / @as(f32, @floatFromInt(input.len)) + self.config.rms_norm_eps);
+        for (input, 0..) |x, i| output[i] = (x / rms) * weight[i];
+    }
+
+    /// Apply RoPE
+    fn applyRope(self: *Self, x: []f32, pos: u32, n_heads: u32) void {
+        const head_dim = self.config.n_embd / self.config.n_head;
+        for (0..n_heads) |h| {
+            const offset = h * head_dim;
+            for (0..head_dim / 2) |i| {
+                const theta = @as(f32, @floatFromInt(pos)) * std.math.pow(f32, self.config.rope_theta, -@as(f32, @floatFromInt(2 * i)) / @as(f32, @floatFromInt(head_dim)));
+                const cos_theta = @cos(theta);
+                const sin_theta = @sin(theta);
+                const x0 = x[offset + 2 * i];
+                const x1 = x[offset + 2 * i + 1];
+                x[offset + 2 * i] = x0 * cos_theta - x1 * sin_theta;
+                x[offset + 2 * i + 1] = x0 * sin_theta + x1 * cos_theta;
+            }
+        }
+    }
+
+    /// Matrix-vector multiplication with SIMD
+    fn matvec(x: []const f32, weight: []const f32, output: []f32, in_features: usize, out_features: usize) void {
+        const Vec = @Vector(8, f32);
+        for (0..out_features) |i| {
+            const row_start = i * in_features;
+            var acc: Vec = @splat(0.0);
+            var j: usize = 0;
+            while (j + 8 <= in_features) : (j += 8) {
+                const x_vec: Vec = x[j..][0..8].*;
+                const w_vec: Vec = weight[row_start + j ..][0..8].*;
+                acc += x_vec * w_vec;
+            }
+            var sum: f32 = @reduce(.Add, acc);
+            while (j < in_features) : (j += 1) sum += x[j] * weight[row_start + j];
+            output[i] = sum;
+        }
+    }
+
+    /// Load F32 attention weights for CPU path (fallback - slow but correct)
+    fn ensureLayerWeightsF32Loaded(self: *Self) !void {
+        if (self.layer_weights_f32 != null) return;
+
+        log.info("Loading F32 attention weights for CPU fallback path...", .{});
+        self.layer_weights_f32 = try self.allocator.alloc(LayerWeightsF32, self.config.n_layer);
+
+        const n_embd = self.config.n_embd;
+        const head_dim = n_embd / self.config.n_head;
+        const kv_dim = self.config.n_head_kv * head_dim;
+
+        var name_buf: [64]u8 = undefined;
+
+        for (0..self.config.n_layer) |layer_idx| {
+            if (layer_idx % 8 == 0) {
+                log.info("  Loading layer {} F32 weights...", .{layer_idx});
+            }
+
+            // Q projection [n_embd, n_embd]
+            const q_proj = try self.allocator.alloc(f32, n_embd * n_embd);
+            var name = try std.fmt.bufPrint(&name_buf, "blk.{}.attn_q.weight", .{layer_idx});
+            try self.loader.dequantizeToF32(name, q_proj);
+
+            // K projection [kv_dim, n_embd]
+            const k_proj = try self.allocator.alloc(f32, kv_dim * n_embd);
+            name = try std.fmt.bufPrint(&name_buf, "blk.{}.attn_k.weight", .{layer_idx});
+            try self.loader.dequantizeToF32(name, k_proj);
+
+            // V projection [kv_dim, n_embd]
+            const v_proj = try self.allocator.alloc(f32, kv_dim * n_embd);
+            name = try std.fmt.bufPrint(&name_buf, "blk.{}.attn_v.weight", .{layer_idx});
+            try self.loader.dequantizeToF32(name, v_proj);
+
+            // O projection [n_embd, n_embd]
+            const o_proj = try self.allocator.alloc(f32, n_embd * n_embd);
+            name = try std.fmt.bufPrint(&name_buf, "blk.{}.attn_output.weight", .{layer_idx});
+            try self.loader.dequantizeToF32(name, o_proj);
+
+            self.layer_weights_f32.?[layer_idx] = LayerWeightsF32{
+                .q_proj = q_proj,
+                .k_proj = k_proj,
+                .v_proj = v_proj,
+                .o_proj = o_proj,
+            };
+        }
+
+        log.info("F32 attention weights loaded (CPU fallback ready)", .{});
+    }
+
+    /// Forward pass for a single token (Hybrid CPU/GPU with batched projections)
+    /// GPU for: Batched Q/K/V/O projections (1 sync each) + MoE FFN (2 syncs)
+    /// CPU for: RMSNorm, RoPE, Attention (fast for single tokens)
+    /// Total: 4 syncs per layer = 128 syncs per token
+    pub fn forward(self: *Self, token_id: u32, pos: u32) ![]const f32 {
+        const n_embd = self.config.n_embd;
+        const head_dim = n_embd / self.config.n_head;
+        const kv_dim = self.config.n_head_kv * head_dim;
+
+        // Use CPU fallback path with dequantized F32 weights (like mixtral_native.zig)
+        // This is slower but numerically correct
+        try self.ensureLayerWeightsF32Loaded();
+
+        // 1. Get token embedding (CPU)
+        try self.ensureEmbeddingsLoaded();
+        const emb_offset = token_id * n_embd;
+        @memcpy(self.hidden_state, self.token_embeddings.?[emb_offset..][0..n_embd]);
+
+        // 2. Process each layer
+        for (0..self.config.n_layer) |layer_idx| {
+            try self.ensureLayerNormsLoaded(layer_idx);
+            const ln = self.layer_norms[layer_idx];
+            const lw = self.layer_weights_f32.?[layer_idx];
+
+            // ==================== ATTENTION BLOCK ====================
+
+            // A. Save residual (CPU)
+            @memcpy(self.residual, self.hidden_state);
+
+            // B. RMSNorm (CPU - fast for single vector)
+            var normed: [4096]f32 = undefined;
+            self.rmsNorm(self.hidden_state, ln.attn_norm.?, normed[0..n_embd]);
+
+            // C. Q/K/V Projections (CPU with F32 weights - like native)
+            matvec(normed[0..n_embd], lw.q_proj, self.q, n_embd, n_embd);
+            matvec(normed[0..n_embd], lw.k_proj, self.k[0..kv_dim], n_embd, kv_dim);
+            matvec(normed[0..n_embd], lw.v_proj, self.v[0..kv_dim], n_embd, kv_dim);
+
+            // DEBUG: Check V output RMS in CPU forward path (layer 0, pos 5 only)
+            if (layer_idx == 0 and pos == 5) {
+                var v_sum_sq: f32 = 0.0;
+                for (0..kv_dim) |i| {
+                    v_sum_sq += self.v[i] * self.v[i];
+                }
+                const v_rms = @sqrt(v_sum_sq / @as(f32, @floatFromInt(kv_dim)));
+                log.info("CPU forward V projection: V RMS={d:.4} (layer 0, pos 5)", .{v_rms});
+                log.info("CPU forward V[0..5]={d:.4},{d:.4},{d:.4},{d:.4},{d:.4}", .{
+                    self.v[0], self.v[1], self.v[2], self.v[3], self.v[4]
+                });
+            }
+
+            // D. RoPE (CPU - fast for single position)
+            self.applyRope(self.q, pos, self.config.n_head);
+            self.applyRope(self.k[0..kv_dim], pos, self.config.n_head_kv);
+
+            // DEBUG: After RoPE - check Q and K values for pos 5
+            if (layer_idx == 0 and pos == 5) {
+                var q_sum_sq: f32 = 0.0;
+                for (0..head_dim) |i| {
+                    q_sum_sq += self.q[i] * self.q[i];
+                }
+                const q_rms = @sqrt(q_sum_sq / @as(f32, @floatFromInt(head_dim)));
+                log.info("CPU forward (after RoPE): Q[head0] RMS={d:.4}", .{q_rms});
+                log.info("CPU forward Q[0..5]={d:.4},{d:.4},{d:.4},{d:.4},{d:.4}", .{
+                    self.q[0], self.q[1], self.q[2], self.q[3], self.q[4]
+                });
+
+                var k_sum_sq: f32 = 0.0;
+                for (0..head_dim) |i| {
+                    k_sum_sq += self.k[i] * self.k[i];
+                }
+                const k_rms = @sqrt(k_sum_sq / @as(f32, @floatFromInt(head_dim)));
+                log.info("CPU forward (after RoPE): K[head0] RMS={d:.4}", .{k_rms});
+                log.info("CPU forward K[0..5]={d:.4},{d:.4},{d:.4},{d:.4},{d:.4}", .{
+                    self.k[0], self.k[1], self.k[2], self.k[3], self.k[4]
+                });
+            }
+
+            // E. Update KV Cache (CPU)
+            const kv_layer_k = self.kv_cache.k_cache[layer_idx];
+            const kv_layer_v = self.kv_cache.v_cache[layer_idx];
+            const cache_offset = pos * kv_dim;
+            @memcpy(kv_layer_k[cache_offset..][0..kv_dim], self.k[0..kv_dim]);
+            @memcpy(kv_layer_v[cache_offset..][0..kv_dim], self.v[0..kv_dim]);
+
+            // F. Grouped Query Attention (CPU - fast for single token)
+            @memset(self.attn_out, 0);
+            const scale = 1.0 / @sqrt(@as(f32, @floatFromInt(head_dim)));
+
+            // DEBUG: Check Q and K magnitudes at generation token (pos=6)
+            if (pos == 6 and layer_idx == 0) {
+                // Check Q vector magnitude (head 0)
+                var q_max: f32 = 0.0;
+                var q_abs_max: f32 = 0.0;
+                for (0..head_dim) |d| {
+                    const q_val = self.q[d];
+                    if (q_val > q_max) q_max = q_val;
+                    if (@abs(q_val) > q_abs_max) q_abs_max = @abs(q_val);
+                }
+
+                // Check K vector magnitude (last position in cache, head 0)
+                const last_k_offset = pos * kv_dim;
+                var k_max: f32 = 0.0;
+                var k_abs_max: f32 = 0.0;
+                for (0..head_dim) |d| {
+                    const k_val = kv_layer_k[last_k_offset + d];
+                    if (k_val > k_max) k_max = k_val;
+                    if (@abs(k_val) > k_abs_max) k_abs_max = @abs(k_val);
+                }
+
+                log.info("=== Q/K MAGNITUDE CHECK (layer=0, pos={}, head=0) ===", .{pos});
+                log.info("  Q_max={d:.4}, Q_abs_max={d:.4} (expected ~0.5)", .{q_max, q_abs_max});
+                log.info("  K_max={d:.4}, K_abs_max={d:.4} (expected ~0.5)", .{k_max, k_abs_max});
+                log.info("  Scale factor: {d:.6} (1/sqrt(128))", .{scale});
+            }
+
+            for (0..self.config.n_head) |h| {
+                const kv_h = h / (self.config.n_head / self.config.n_head_kv);
+                const q_offset = h * head_dim;
+                const out_offset = h * head_dim;
+
+                var scores: [4096]f32 = undefined;
+                var max_score: f32 = -std.math.inf(f32);
+
+                // DEBUG: Print raw Q·K for first head at generation token
+                var debug_raw_qk: f32 = 0.0;
+                if (pos == 6 and layer_idx == 0 and h == 0) {
+                    const k_offset_debug = pos * kv_dim + kv_h * head_dim;
+                    for (0..head_dim) |d| {
+                        debug_raw_qk += self.q[q_offset + d] * kv_layer_k[k_offset_debug + d];
+                    }
+                    log.info("  RAW Q·K (before scale): {d:.2} (expected 20-500)", .{debug_raw_qk});
+                    log.info("  SCALED Q·K (after 1/sqrt(128)): {d:.2} (expected 0.2-4.0)", .{debug_raw_qk * scale});
+                }
+
+                for (0..pos + 1) |p| {
+                    const k_offset = p * kv_dim + kv_h * head_dim;
+                    var score: f32 = 0.0;
+                    for (0..head_dim) |d| score += self.q[q_offset + d] * kv_layer_k[k_offset + d];
+                    score *= scale;
+                    scores[p] = score;
+                    if (score > max_score) max_score = score;
+                }
+
+                // DEBUG: Print CPU attention scores at layer 0, pos 5
+                if (layer_idx == 0 and pos == 5 and h == 0) {
+                    std.debug.print("CPU ATTN DEBUG L0: RAW scores head0 [0..6]=[", .{});
+                    for (0..pos + 1) |i| std.debug.print("{d:.2},", .{scores[i]});
+                    std.debug.print("]\n", .{});
+
+                    // Check V[pos=0] and V[pos=5] RMS
+                    var v0_sum_sq: f32 = 0;
+                    var v5_sum_sq: f32 = 0;
+                    const v0_offset = 0 * kv_dim + kv_h * head_dim;
+                    const v5_offset = 5 * kv_dim + kv_h * head_dim;
+                    for (0..head_dim) |d| {
+                        v0_sum_sq += kv_layer_v[v0_offset + d] * kv_layer_v[v0_offset + d];
+                        v5_sum_sq += kv_layer_v[v5_offset + d] * kv_layer_v[v5_offset + d];
+                    }
+                    const v0_rms = @sqrt(v0_sum_sq / @as(f32, @floatFromInt(head_dim)));
+                    const v5_rms = @sqrt(v5_sum_sq / @as(f32, @floatFromInt(head_dim)));
+                    log.info("CPU V[pos0,head0] RMS={d:.4}, V[pos5,head0] RMS={d:.4}", .{v0_rms, v5_rms});
+
+                    // Check full V cache RMS (all positions, all heads)
+                    var v_full_sum_sq: f32 = 0;
+                    for (0..pos + 1) |p| {
+                        for (0..kv_dim) |i| {
+                            v_full_sum_sq += kv_layer_v[p * kv_dim + i] * kv_layer_v[p * kv_dim + i];
+                        }
+                    }
+                    const v_full_rms = @sqrt(v_full_sum_sq / @as(f32, @floatFromInt((pos + 1) * kv_dim)));
+                    log.info("CPU V_cache full RMS (all pos, all heads)={d:.4}", .{v_full_rms});
+                }
+
+                var sum_exp: f32 = 0.0;
+                for (0..pos + 1) |p| {
+                    scores[p] = @exp(scores[p] - max_score);
+                    sum_exp += scores[p];
+                }
+                for (0..pos + 1) |p| scores[p] /= sum_exp;
+
+                for (0..pos + 1) |p| {
+                    const v_offset = p * kv_dim + kv_h * head_dim;
+                    for (0..head_dim) |d| {
+                        self.attn_out[out_offset + d] += scores[p] * kv_layer_v[v_offset + d];
+                    }
+                }
+            }
+
+            // G. O Projection (CPU with F32 weights)
+            var o_out: [4096]f32 = undefined;
+            matvec(self.attn_out, lw.o_proj, o_out[0..n_embd], n_embd, n_embd);
+
+            // H. Residual Add (CPU)
+            for (0..n_embd) |i| self.hidden_state[i] = self.residual[i] + o_out[i];
+
+            // DEBUG: Check hidden state after attention block at layer 0, pos 5
+            if (layer_idx == 0 and pos == 5) {
+                var attn_out_sum_sq: f32 = 0;
+                var o_out_sum_sq: f32 = 0;
+                var hidden_sum_sq: f32 = 0;
+                var residual_sum_sq: f32 = 0;
+                for (0..n_embd) |i| {
+                    attn_out_sum_sq += self.attn_out[i] * self.attn_out[i];
+                    o_out_sum_sq += o_out[i] * o_out[i];
+                    hidden_sum_sq += self.hidden_state[i] * self.hidden_state[i];
+                    residual_sum_sq += self.residual[i] * self.residual[i];
+                }
+                const attn_out_rms = @sqrt(attn_out_sum_sq / @as(f32, @floatFromInt(n_embd)));
+                const o_out_rms = @sqrt(o_out_sum_sq / @as(f32, @floatFromInt(n_embd)));
+                const hidden_rms = @sqrt(hidden_sum_sq / @as(f32, @floatFromInt(n_embd)));
+                const residual_rms = @sqrt(residual_sum_sq / @as(f32, @floatFromInt(n_embd)));
+                log.info("CPU Layer 0 ATTENTION BLOCK OUTPUT:", .{});
+                log.info("  attn_out RMS={d:.4}, o_out RMS={d:.4}", .{attn_out_rms, o_out_rms});
+                log.info("  residual RMS={d:.4}, hidden_state RMS={d:.4}", .{residual_rms, hidden_rms});
+            }
+
+            // ==================== MOE BLOCK ====================
+
+            // A. Save residual (CPU)
+            @memcpy(self.residual, self.hidden_state);
+
+            // B. RMSNorm (CPU)
+            self.rmsNorm(self.hidden_state, ln.ffn_norm.?, self.hidden_state);
+
+            // C. MoE FFN (GPU - 2 syncs for router + experts)
+            try self.ensureMoEPointersLoaded(layer_idx);
+            const mp = self.moe_pointers[layer_idx];
+
+            var gate_arr: [8][]const u8 = undefined;
+            var up_arr: [8][]const u8 = undefined;
+            var down_arr: [8][]const u8 = undefined;
+            for (0..8) |e| {
+                gate_arr[e] = mp.gate[e] orelse &[_]u8{};
+                up_arr[e] = mp.up[e] orelse &[_]u8{};
+                down_arr[e] = mp.down[e] orelse &[_]u8{};
+            }
+
+            // Use moeFFN_Q4_Batched (batch_size=1) - same as working native engine
+            // This correctly handles F16 router weights used in Mixtral Q4_K_M
+            const moe_output = try self.moe_engine.moeFFN_Q4_Batched(
+                self.allocator,
+                self.hidden_state,
+                1, // batch_size = 1
+                mp.router orelse &[_]u8{},
+                gate_arr,
+                up_arr,
+                down_arr,
+                self.config.n_expert,
+                n_embd,
+                self.config.n_ff,
+            );
+            defer self.allocator.free(moe_output);
+
+            // D. Residual Add (CPU)
+            for (0..n_embd) |i| self.hidden_state[i] = self.residual[i] + moe_output[i];
+
+            // DEBUG: Track hidden state signature after each layer for pos=5
+            if (pos == 5) {
+                var sum: f32 = 0;
+                var sum_sq: f32 = 0;
+                for (0..n_embd) |i| {
+                    sum += self.hidden_state[i];
+                    sum_sq += self.hidden_state[i] * self.hidden_state[i];
+                }
+                const mean = sum / @as(f32, @floatFromInt(n_embd));
+                const rms = @sqrt(sum_sq / @as(f32, @floatFromInt(n_embd)));
+                std.debug.print("CPU Layer {d:2}: mean={d:8.4} rms={d:8.4} h[0..3]=[{d:.4},{d:.4},{d:.4}]\n", .{
+                    layer_idx, mean, rms, self.hidden_state[0], self.hidden_state[1], self.hidden_state[2]
+                });
+            }
+        }
+
+        // 3. Final RMSNorm + output projection (CPU)
+        try self.ensureOutputLoaded();
+
+        var final_normed: [4096]f32 = undefined;
+        self.rmsNorm(self.hidden_state, self.output_norm.?, final_normed[0..n_embd]);
+        matvec(final_normed[0..n_embd], self.output_weight.?, self.logits, n_embd, self.config.n_vocab);
+
+        return self.logits;
+    }
+
+    /// Single Submit forward pass - reduced sync architecture
+    /// Target: Reduce syncs from 128 (4/layer) to 32 (1/layer) using:
+    /// - GPU-resident attention weights
+    /// - GQA kernels for all heads in parallel
+    /// - Single command buffer per layer for attention block
+    /// MoE still requires sync for weight loading (future: Managed Memory)
+    pub fn forwardSingleSubmit(self: *Self, token_id: u32, pos: u32) ![]const f32 {
+        const n_embd = self.config.n_embd;
+        const n_head = self.config.n_head;
+        const n_head_kv = self.config.n_head_kv;
+        const head_dim = n_embd / n_head;
+        const kv_dim = n_head_kv * head_dim;
+        const seq_len = pos + 1;
+
+        // Ensure GPU-resident attention weights are uploaded
+        try self.uploadResidentAttention();
+
+        // Initialize GPU KV cache if needed (one-time per layer)
+        for (0..self.config.n_layer) |layer_idx| {
+            try self.moe_engine.initKVCache(@intCast(layer_idx), @intCast(self.config.n_ctx), @intCast(kv_dim));
+        }
+
+        // 1. Upload embedding to GPU buf_residual
+        try self.ensureEmbeddingsLoaded();
+        const emb_offset = token_id * n_embd;
