+//! Native Mixtral Inference Engine
+//!
+//! Full native Zig inference without llama.cpp dependency.
+//! Uses Metal GPU for all compute-intensive operations.
+//!
+//! Architecture:
+//! - Token embeddings from GGUF
+//! - RMSNorm, RoPE, Attention, MoE FFN on Metal GPU
+//! - Output projection and sampling
+//!
+//! Performance target: 3-5 tok/s on 16GB M2 with optimizations
+
+const std = @import("std");
+const gguf = @import("inference/gguf_loader.zig");
+const moe_metal = @import("moe_metal.zig");
+const moe = @import("moe.zig");
+
+const BF16 = gguf.BF16;
+const log = std.log.scoped(.mixtral_native);
+
+/// Mixtral model configuration
+pub const MixtralConfig = struct {
+    n_vocab: u32 = 32000,
+    n_ctx: u32 = 4096,
+    n_embd: u32 = 4096,
+    n_head: u32 = 32,
+    n_head_kv: u32 = 8,
+    n_layer: u32 = 32,
+    n_ff: u32 = 14336,
+    n_expert: u32 = 8,
+    n_expert_used: u32 = 2,
+    rope_theta: f32 = 1000000.0,
+    rms_norm_eps: f32 = 1e-5,
+};
+
+/// KV Cache for attention
+pub const KVCache = struct {
+    allocator: std.mem.Allocator,
+    k_cache: [][]f32, // [n_layer][n_head_kv * n_ctx * head_dim]
+    v_cache: [][]f32, // [n_layer][n_head_kv * n_ctx * head_dim]
+    seq_len: u32,
+    n_ctx: u32,
+    head_dim: u32,
+    n_head_kv: u32,
+    n_layer: u32,
+
+    pub fn init(allocator: std.mem.Allocator, config: MixtralConfig) !*KVCache {
+        const self = try allocator.create(KVCache);
+        errdefer allocator.destroy(self);
+
+        const head_dim = config.n_embd / config.n_head;
+        const cache_size = config.n_head_kv * config.n_ctx * head_dim;
+
+        self.k_cache = try allocator.alloc([]f32, config.n_layer);
+        errdefer allocator.free(self.k_cache);
+
+        self.v_cache = try allocator.alloc([]f32, config.n_layer);
+        errdefer {
+            for (self.k_cache) |k| allocator.free(k);
+            allocator.free(self.v_cache);
+        }
+
+        for (0..config.n_layer) |i| {
+            self.k_cache[i] = try allocator.alloc(f32, cache_size);
+            @memset(self.k_cache[i], 0);
+        }
+
+        for (0..config.n_layer) |i| {
+            self.v_cache[i] = try allocator.alloc(f32, cache_size);
+            @memset(self.v_cache[i], 0);
+        }
+
+        self.allocator = allocator;
+        self.seq_len = 0;
+        self.n_ctx = config.n_ctx;
+        self.head_dim = head_dim;
+        self.n_head_kv = config.n_head_kv;
+        self.n_layer = config.n_layer;
+
+        return self;
+    }
+
+    pub fn deinit(self: *KVCache) void {
+        for (self.k_cache) |k| self.allocator.free(k);
+        for (self.v_cache) |v| self.allocator.free(v);
+        self.allocator.free(self.k_cache);
+        self.allocator.free(self.v_cache);
+        self.allocator.destroy(self);
+    }
+
+    pub fn clear(self: *KVCache) void {
+        self.seq_len = 0;
+        for (self.k_cache) |k| @memset(k, 0);
+        for (self.v_cache) |v| @memset(v, 0);
+    }
+};
+
+/// Native Mixtral inference engine
+pub const MixtralNativeEngine = struct {
+    allocator: std.mem.Allocator,
+    config: MixtralConfig,
+
+    // GGUF loader for weight access
+    loader: *gguf.GGUFLoader,
+
+    // Metal MoE engine for expert computation
+    moe_engine: *moe_metal.MetalMoEEngine,
+
+    // Token embeddings [n_vocab, n_embd] - loaded to memory
+    token_embeddings: []f32,
+
+    // Output weights
+    output_norm: []f32,     // [n_embd]
+    output_weight: []f32,   // [n_vocab, n_embd]
+
+    // Layer weights - preloaded for all layers to avoid disk I/O during inference
+    // Each layer has: attn_norm, ffn_norm, q/k/v/o_proj, moe_gate, expert weights
+    layer_weights: []LayerWeights,
+
+    // Working buffers
+    hidden_state: []f32,    // [n_embd]
+    residual: []f32,        // [n_embd]
+    attn_out: []f32,        // [n_embd]
+    q: []f32,               // [n_head * head_dim]
