+        if (self.layer_weights) |*lw| {
+            for (0..8) |i| {
+                expert_gate[i] = lw.expert_gate_weights[i];
+                expert_up[i] = lw.expert_up_weights[i];
+                expert_down[i] = lw.expert_down_weights[i];
+            }
