+            log.info("Starting native inference with {} input tokens...", .{tokens.len});
+
+            // Generate response - limit to just 5 tokens for faster testing
+            const start_time = std.time.milliTimestamp();
+            const generated_tokens = try native.generate(
+                tokens,
+                5, // max_new_tokens - reduced for faster testing
+                0.7, // temperature
+                null, // no callback
+            );
+            defer self.allocator.free(generated_tokens);
