+            const gen_time = std.time.milliTimestamp() - start_time;
+            const tok_per_sec = if (gen_time > 0)
+                @as(f32, @floatFromInt(generated_tokens.len)) / (@as(f32, @floatFromInt(gen_time)) / 1000.0)
+            else
+                0.0;
+            log.info("Generated {} tokens in {}ms ({d:.1} tok/s)", .{ generated_tokens.len, gen_time, tok_per_sec });
