+
+        _ = try stream.write(header);
+        _ = try stream.write(response_body);
+    }
+
+    fn sendError(self: *MoEServer, stream: std.net.Stream, code: u16, message: []const u8) !void {
+        _ = self;
+        var response_buf: [1024]u8 = undefined;
+        const body = try std.fmt.bufPrint(&response_buf,
+            \\{{"error":{{"message":"{s}","type":"error","code":{d}}}}}
+        , .{message, code});
+
+        var header_buf: [256]u8 = undefined;
+        const header = try std.fmt.bufPrint(&header_buf,
+            "HTTP/1.1 {d} Error\r\n" ++
+            "Content-Type: application/json\r\n" ++
+            "Content-Length: {}\r\n" ++
+            "Connection: close\r\n" ++
+            "\r\n"
+        , .{code, body.len});
+
+        _ = try stream.write(header);
+        _ = try stream.write(body);
+    }
+
+    fn send404(self: *MoEServer, stream: std.net.Stream) !void {
+        try self.sendError(stream, 404, "Not found");
+    }
+};
+
+/// Run MoE server (called from main.zig runServer when MoE model detected)
+pub fn runMoEServer(
+    allocator: std.mem.Allocator,
+    model_path: []const u8,
+    host: []const u8,
+    port: u16,
+    prof: profile_mod.Profile,
+) !void {
+    var server = try MoEServer.init(allocator, model_path, prof);
+    defer server.deinit();
+
+    try server.start(host, port);
+}

