+
+    if (args.len < 2) {
+        std.debug.print("Usage: {s} <model.gguf>\n", .{args[0]});
+        return error.MissingArgument;
+    }
+
+    const model_path = args[1];
+
+    std.debug.print("\n=== 4-Layer Batching Test ===\n\n", .{});
+    std.debug.print("Model: {s}\n\n", .{model_path});
+
+    // Load GGUF
+    std.debug.print("Memory-mapping GGUF file...\n", .{});
+    var loader = try gguf_loader.GGUFLoader.init(allocator, model_path);
+    defer loader.deinit();
+    std.debug.print("  File mapped: {} MB\n\n", .{loader.mmap_len / (1024 * 1024)});
+
+    // Initialize Metal engine
+    std.debug.print("Initializing Metal GPU engine...\n", .{});
+    var moe_engine = try moe_metal.MetalMoEEngine.init(allocator);
+    defer moe_engine.deinit();
+
+    // Initialize lazy Mixtral engine
+    std.debug.print("Initializing lazy Mixtral engine...\n\n", .{});
+    var engine = try mixtral_lazy.MixtralLazyEngine.init(allocator, &loader, moe_engine);
+    defer engine.deinit();
+
+    // THE PARIS TEST: "The capital of France is"
+    std.debug.print("=== THE PARIS TEST ===\n", .{});
+    std.debug.print("Prompt: <s> The capital of France is\n", .{});
+    std.debug.print("Expected: ' Paris' or similar (NOT token 1823)\n\n", .{});
+
+    // Prompt tokens: "<s> The capital of France is"
+    // Correct tokens for Mixtral tokenizer
+    const prompt = [_]u32{ 1, 415, 5565, 302, 4843, 349 }; // <s> The capital of France is
+
+    std.debug.print("--- Processing prompt ---\n", .{});
+    var logits: []const f32 = undefined;
+    for (prompt, 0..) |token, pos| {
+        const token_start = std.time.milliTimestamp();
+        logits = try engine.forwardTrueSingleSubmit(token, @intCast(pos));
+        const token_elapsed = std.time.milliTimestamp() - token_start;
+        std.debug.print("  Pos {}: token {} ({} ms)\n", .{ pos, token, token_elapsed });
+    }
+
+    // Generate completion (use logits from last prompt token)
