+            max_val = logits[i];
+            max_idx = @intCast(i);
+        }
+    }
+    std.debug.print("  Top token: {} (logit: {d:.4})\n", .{ max_idx, max_val });
+
+    // DEBUG: Print top 5 tokens
+    std.debug.print("\n  Top 5 logits for debugging:\n", .{});
+    var top_logits: [5]struct { token: u32, logit: f32 } = undefined;
+    for (0..5) |i| {
+        var best_idx: u32 = 0;
+        var best_val: f32 = -std.math.inf(f32);
+        for (0..engine.config.n_vocab) |j| {
+            var already_used = false;
+            for (0..i) |k| {
+                if (top_logits[k].token == j) {
+                    already_used = true;
+                    break;
+                }
+            }
+            if (!already_used and logits[j] > best_val) {
+                best_val = logits[j];
+                best_idx = @intCast(j);
+            }
+        }
+        top_logits[i] = .{ .token = best_idx, .logit = best_val };
+        std.debug.print("    {}: token {} (logit: {d:.4})\n", .{ i + 1, best_idx, best_val });
+    }
