+    var total_time: i64 = 0;
+
+    for (0..15) |i| {
+        const token_start = std.time.milliTimestamp();
+        const current_pos = prompt.len + i; // Position of current token
+        const next_logits = try engine.forwardTrueSingleSubmit(generated_tokens[i], @intCast(current_pos));
+        const token_elapsed = std.time.milliTimestamp() - token_start;
+        total_time += token_elapsed;
+
+        // Greedy sampling for next token
+        var next_max_idx: u32 = 0;
+        var next_max_val: f32 = next_logits[0];
+        for (1..engine.config.n_vocab) |j| {
+            if (next_logits[j] > next_max_val) {
+                next_max_val = next_logits[j];
+                next_max_idx = @intCast(j);
+            }
+        }
+
+        // DEBUG: Print top 3 logits for first few tokens
+        if (i < 3) {
+            var top3: [3]struct{tok: u32, val: f32} = undefined;
+            for (0..3) |k| {
+                var best_tok: u32 = 0;
+                var best_val: f32 = -std.math.inf(f32);
+                for (0..engine.config.n_vocab) |j| {
+                    var used = false;
+                    for (0..k) |m| { if (top3[m].tok == j) { used = true; break; } }
+                    if (!used and next_logits[j] > best_val) {
+                        best_val = next_logits[j];
+                        best_tok = @intCast(j);
+                    }
+                }
+                top3[k] = .{.tok = best_tok, .val = best_val};
+            }
+            std.debug.print("    Top3: {}({d:.2}), {}({d:.2}), {}({d:.2})\n", .{top3[0].tok, top3[0].val, top3[1].tok, top3[1].val, top3[2].tok, top3[2].val});
+        }
+
+        generated_tokens[i + 1] = next_max_idx;
+        std.debug.print("  Token {}: {} (logit: {d:.2}, {d:.2} tok/s)\n", .{ i + 1, next_max_idx, next_max_val, 1000.0 / @as(f64, @floatFromInt(token_elapsed)) });
+    }
+
+    const avg_time = @divTrunc(total_time, 15);
+    std.debug.print("\n=== Results ===\n", .{});
+    std.debug.print("Generated sequence: {any}\n", .{generated_tokens});
+    std.debug.print("Average: {} ms/tok\n", .{avg_time});
+    std.debug.print("Throughput: {d:.2} tok/s\n", .{1000.0 / @as(f64, @floatFromInt(avg_time))});
+    std.debug.print("Target: 2-5 tok/s\n", .{});
+
+    // Check for repetition
+    var has_rep = false;
+    for (0..generated_tokens.len - 2) |j| {
+        if (generated_tokens[j] == generated_tokens[j + 1]) {
+            has_rep = true;
+            break;
+        }
+    }
+    if (has_rep) {
+        std.debug.print("\n⚠️  Repetition detected - possible attention collapse\n", .{});
+    }
+
+    if (avg_time < 500) {
+        std.debug.print("\n✅ SUCCESS: Achieved target performance!\n", .{});
+    } else if (avg_time < 2000) {
+        std.debug.print("\n⚠️  PARTIAL: Better than before but below target.\n", .{});
+    } else {
+        std.debug.print("\n❌ SLOW: Still thrashing, need more optimization.\n", .{});
+    }
+}

