+//! Diagnostic test: Compare CPU vs GPU Q projection (Q4_K)
+//! This isolates the exact point of divergence
+
+const std = @import("std");
+const mixtral_lazy = @import("mixtral_lazy.zig");
+const gguf_loader = @import("inference/gguf_loader.zig");
+const moe_metal = @import("moe_metal.zig");
+const objc = @import("inference/metal/objc.zig");
+
+pub fn main() !void {
+    var gpa = std.heap.GeneralPurposeAllocator(.{}){};
+    defer _ = gpa.deinit();
+    const allocator = gpa.allocator();
+
+    const args = try std.process.argsAlloc(allocator);
+    defer std.process.argsFree(allocator, args);
+
+    if (args.len < 2) {
+        std.debug.print("Usage: {s} <model.gguf>\n", .{args[0]});
+        return error.MissingArgument;
+    }
+    const model_path = args[1];
+
+    std.debug.print("\n=== CPU vs GPU Q Projection (Q4_K) Comparison ===\n", .{});
+
+    // Load model
+    var loader = try gguf_loader.GGUFLoader.init(allocator, model_path);
+    defer loader.deinit();
+
+    var moe_engine = try moe_metal.MetalMoEEngine.init(allocator);
+    defer moe_engine.deinit();
+
+    // Get layer 0 Q weights (Q4_K format)
+    const q_weight_data = loader.getTensorDataByName("blk.0.attn_q.weight") orelse return error.NotFound;
+    std.debug.print("Q weight size: {} bytes\n", .{q_weight_data.len});
+
+    // Check tensor info
+    if (loader.getTensor("blk.0.attn_q.weight")) |info| {
+        std.debug.print("Q weight type: {}\n", .{info.type_});
+        std.debug.print("Q weight n_elements: {}\n", .{info.numElements()});
+    }
+
+    // Upload to GPU
+    const q_weight_buf = moe_engine.uploadBuffer(q_weight_data) orelse return error.BufferFailed;
+
+    // Create a test input - use a simple pattern
+    const n_embd: usize = 4096;
+
+    var test_input: [4096]f32 = undefined;
+    // Simple pattern: input[i] = sin(i * 0.01) to have varied values
+    for (0..n_embd) |i| {
+        test_input[i] = @sin(@as(f32, @floatFromInt(i)) * 0.01);
+    }
+
+    std.debug.print("Input[0..5] = {d:.4}, {d:.4}, {d:.4}, {d:.4}, {d:.4}\n", .{
+        test_input[0], test_input[1], test_input[2], test_input[3], test_input[4]
+    });
+
+    // ============ CPU PATH ============
+    std.debug.print("\n--- CPU Path (F32 dequantized) ---\n", .{});
+
+    // Dequantize Q weights to F32
+    const q_proj_f32 = try allocator.alloc(f32, n_embd * n_embd);
+    defer allocator.free(q_proj_f32);
+
+    try loader.dequantizeToF32("blk.0.attn_q.weight", q_proj_f32);
+    std.debug.print("Dequantized Q weights, first 5: {d:.6}, {d:.6}, {d:.6}, {d:.6}, {d:.6}\n", .{
+        q_proj_f32[0], q_proj_f32[1], q_proj_f32[2], q_proj_f32[3], q_proj_f32[4]
+    });
+
+    // CPU matvec: output[i] = sum(input[j] * weight[i * n_in + j])
+    var cpu_output: [4096]f32 = undefined;
+    for (0..n_embd) |i| {
+        var sum: f32 = 0.0;
+        const row_start = i * n_embd;
+        for (0..n_embd) |j| {
+            sum += test_input[j] * q_proj_f32[row_start + j];
+        }
+        cpu_output[i] = sum;
+    }
+
+    std.debug.print("CPU output[0..5] = {d:.6}, {d:.6}, {d:.6}, {d:.6}, {d:.6}\n", .{
+        cpu_output[0], cpu_output[1], cpu_output[2], cpu_output[3], cpu_output[4]
+    });
+
+    // ============ GPU PATH ============
+    std.debug.print("\n--- GPU Path (Q4_K on GPU) ---\n", .{});
+
+    // Upload input to GPU
+    moe_engine.uploadToBuffer(moe_engine.buf_normed, &test_input);
+
+    // Run GPU Q projection (Q4_K kernel)
+    const cmd_buf = moe_engine.createCommandBuffer() orelse return error.CommandBufferFailed;
+    try moe_engine.encodeDenseQ4K(cmd_buf, q_weight_buf, moe_engine.buf_normed, moe_engine.buf_q, @intCast(n_embd), @intCast(n_embd));
+    moe_engine.commitAndWait(cmd_buf);
+
+    // Read GPU output
+    const gpu_output_ptr: [*]f32 = @ptrCast(@alignCast(objc.bufferContents(moe_engine.buf_q)));
+    const gpu_output = gpu_output_ptr[0..n_embd];
+
+    std.debug.print("GPU output[0..5] = {d:.6}, {d:.6}, {d:.6}, {d:.6}, {d:.6}\n", .{
+        gpu_output[0], gpu_output[1], gpu_output[2], gpu_output[3], gpu_output[4]
+    });
+
+    // ============ COMPARISON ============
+    std.debug.print("\n--- Comparison ---\n", .{});
+
+    var max_diff: f32 = 0.0;
+    var max_diff_idx: usize = 0;
+    var sum_diff: f32 = 0.0;
+    var sum_cpu_sq: f32 = 0.0;
+
+    for (0..n_embd) |i| {
+        const diff = @abs(cpu_output[i] - gpu_output[i]);
+        sum_diff += diff;
+        sum_cpu_sq += cpu_output[i] * cpu_output[i];
+        if (diff > max_diff) {
+            max_diff = diff;
+            max_diff_idx = i;
+        }
+    }
+
+    const avg_diff = sum_diff / @as(f32, @floatFromInt(n_embd));
+    const cpu_rms = @sqrt(sum_cpu_sq / @as(f32, @floatFromInt(n_embd)));
+    const relative_error = avg_diff / cpu_rms * 100.0;
+
+    std.debug.print("Max diff: {d:.6} at index {}\n", .{max_diff, max_diff_idx});
+    std.debug.print("Avg diff: {d:.6}\n", .{avg_diff});
+    std.debug.print("CPU RMS: {d:.6}\n", .{cpu_rms});
+    std.debug.print("Relative error: {d:.2}%\n", .{relative_error});
+
+    // Show worst case comparison
+    std.debug.print("\nWorst case (idx {}): CPU={d:.6}, GPU={d:.6}, diff={d:.6}\n", .{
+        max_diff_idx,
+        cpu_output[max_diff_idx],
+        gpu_output[max_diff_idx],
+        @abs(cpu_output[max_diff_idx] - gpu_output[max_diff_idx])
+    });
+
+    if (relative_error < 1.0) {
+        std.debug.print("\n✅ CPU and GPU match within 1%!\n", .{});
+    } else if (relative_error < 10.0) {
+        std.debug.print("\n⚠️ CPU and GPU differ by {d:.2}% - quantization noise?\n", .{relative_error});
+    } else {
+        std.debug.print("\n❌ CPU and GPU differ by {d:.2}% - BUG DETECTED!\n", .{relative_error});
+    }
+
+    // Also test K/V projections for completeness
+    std.debug.print("\n\n=== Testing K Projection (Q8_0) ===\n", .{});
+
+    const k_weight_data = loader.getTensorDataByName("blk.0.attn_k.weight") orelse return error.NotFound;
+    const k_weight_buf = moe_engine.uploadBuffer(k_weight_data) orelse return error.BufferFailed;
+
+    const kv_dim: usize = 1024;
+    const k_proj_f32 = try allocator.alloc(f32, kv_dim * n_embd);
+    defer allocator.free(k_proj_f32);
+    try loader.dequantizeToF32("blk.0.attn_k.weight", k_proj_f32);
+
+    var cpu_k_output: [1024]f32 = undefined;
+    for (0..kv_dim) |i| {
+        var sum: f32 = 0.0;
+        const row_start = i * n_embd;
+        for (0..n_embd) |j| {
+            sum += test_input[j] * k_proj_f32[row_start + j];
+        }
+        cpu_k_output[i] = sum;
+    }
+
+    const cmd_buf2 = moe_engine.createCommandBuffer() orelse return error.CommandBufferFailed;
+    try moe_engine.encodeDenseQ8_0(cmd_buf2, k_weight_buf, moe_engine.buf_normed, moe_engine.buf_k, @intCast(kv_dim), @intCast(n_embd));
+    moe_engine.commitAndWait(cmd_buf2);
+
+    const gpu_k_ptr: [*]f32 = @ptrCast(@alignCast(objc.bufferContents(moe_engine.buf_k)));
+    var k_max_diff: f32 = 0.0;
+    var k_sum_diff: f32 = 0.0;
+    var k_sum_sq: f32 = 0.0;
+    for (0..kv_dim) |i| {
+        const diff = @abs(cpu_k_output[i] - gpu_k_ptr[i]);
+        k_sum_diff += diff;
+        k_sum_sq += cpu_k_output[i] * cpu_k_output[i];
+        if (diff > k_max_diff) k_max_diff = diff;
+    }
+    const k_rel_err = (k_sum_diff / @as(f32, @floatFromInt(kv_dim))) / @sqrt(k_sum_sq / @as(f32, @floatFromInt(kv_dim))) * 100.0;
+    std.debug.print("K projection relative error: {d:.2}%\n", .{k_rel_err});
+
+    // Test V too
+    std.debug.print("\n=== Testing V Projection (Q8_0) ===\n", .{});
+
+    const v_weight_data = loader.getTensorDataByName("blk.0.attn_v.weight") orelse return error.NotFound;
+    const v_weight_buf = moe_engine.uploadBuffer(v_weight_data) orelse return error.BufferFailed;
+
