+//! Test lazy-loading Mixtral inference
+//! Run: zig build test-lazy-mixtral
+
+const std = @import("std");
+const mixtral_lazy = @import("mixtral_lazy.zig");
+const gguf_loader = @import("inference/gguf_loader.zig");
+const moe_metal = @import("moe_metal.zig");
+
+fn hasNaN(slice: []const f32) bool {
+    for (slice) |v| {
+        if (std.math.isNan(v)) return true;
+    }
+    return false;
+}
+
+fn printStats(name: []const u8, slice: []const f32) void {
+    var min: f32 = std.math.inf(f32);
+    var max: f32 = -std.math.inf(f32);
+    var sum: f32 = 0;
+    var nan_count: usize = 0;
+    for (slice) |v| {
+        if (std.math.isNan(v)) {
+            nan_count += 1;
+        } else {
+            if (v < min) min = v;
+            if (v > max) max = v;
+            sum += v;
+        }
+    }
+    const mean = sum / @as(f32, @floatFromInt(slice.len - nan_count));
+    std.debug.print("  {s}: min={d:.4}, max={d:.4}, mean={d:.4}, nans={}\n", .{ name, min, max, mean, nan_count });
+}
+
