+//! Verify GPU matmul matches CPU for Q/K projections
+//! IMPORTANT: This test directly calls the Q4_K matmul kernel, NOT the full forward pass,
+//! because the full forward also applies RoPE which modifies Q.
+
+const std = @import("std");
+const mixtral_lazy = @import("mixtral_lazy.zig");
+const gguf_loader = @import("inference/gguf_loader.zig");
+const moe_metal = @import("moe_metal.zig");
+const objc = @import("inference/metal/objc.zig");
+
+pub fn main() !void {
+    var gpa = std.heap.GeneralPurposeAllocator(.{}){};
+    defer _ = gpa.deinit();
+    const allocator = gpa.allocator();
+
+    const args = try std.process.argsAlloc(allocator);
+    defer std.process.argsFree(allocator, args);
+
+    if (args.len < 2) {
+        std.debug.print("Usage: {s} <model.gguf>\n", .{args[0]});
+        return error.MissingArgument;
+    }
+
+    std.debug.print("\n=== GPU Matmul Verification Test ===\n\n", .{});
+
+    // Load GGUF
+    var loader = try gguf_loader.GGUFLoader.init(allocator, args[1]);
+    defer loader.deinit();
+
+    // Initialize Metal engine
+    var moe_engine = try moe_metal.MetalMoEEngine.init(allocator);
+    defer moe_engine.deinit();
+
+    const n_embd: usize = 4096;
+
+    // Load token embeddings (for BOS token input)
+    std.debug.print("Loading token embeddings...\n", .{});
+    const token_embeddings = try allocator.alloc(f32, 32000 * n_embd);
+    defer allocator.free(token_embeddings);
+    try loader.dequantizeToF32("token_embd.weight", token_embeddings);
+
+    // Get BOS embedding (token 1)
+    const input = token_embeddings[n_embd .. 2 * n_embd];
+    std.debug.print("BOS embedding (first 10): ", .{});
+    for (0..10) |i| std.debug.print("{d:.4} ", .{input[i]});
+    std.debug.print("\n", .{});
+
+    // 2. Get attention norm weights
+    const attn_norm = try allocator.alloc(f32, n_embd);
+    defer allocator.free(attn_norm);
+    try loader.dequantizeToF32("blk.0.attn_norm.weight", attn_norm);
+
+    // 3. Apply RMSNorm
+    var sum_sq: f32 = 0;
+    for (input) |x| sum_sq += x * x;
+    const rms = @sqrt(sum_sq / @as(f32, n_embd) + 1e-5);
+
+    const normed = try allocator.alloc(f32, n_embd);
+    defer allocator.free(normed);
+    for (input, 0..) |x, i| normed[i] = (x / rms) * attn_norm[i];
+
+    std.debug.print("\nNormed input (first 10): ", .{});
+    for (0..10) |i| std.debug.print("{d:.4} ", .{normed[i]});
+    std.debug.print("\n", .{});
+
+    // 4. Get raw Q4_K weight data and upload to GPU
+    const q_weight_raw = loader.getTensorDataByName("blk.0.attn_q.weight") orelse return error.TensorNotFound;
+    std.debug.print("\nQ weight raw bytes: {} bytes\n", .{q_weight_raw.len});
+
+    // Upload weights to GPU
+    const q_weight_buf = moe_engine.uploadBuffer(q_weight_raw) orelse return error.BufferUploadFailed;
+    defer objc.release(q_weight_buf);
+
+    // Upload normed input to GPU
+    const normed_bytes = std.mem.sliceAsBytes(normed);
+    const normed_buf = moe_engine.uploadBuffer(normed_bytes) orelse return error.BufferUploadFailed;
+    defer objc.release(normed_buf);
+
+    // Run GPU Q4_K matmul
+    std.debug.print("Running GPU Q4_K matmul...\n", .{});
+    try moe_engine.denseMatVecQ4K(q_weight_buf, normed_buf, moe_engine.buf_q, @intCast(n_embd), @intCast(n_embd));
+
+    // Read GPU result
+    const q_gpu: [*]f32 = @ptrCast(@alignCast(objc.bufferContents(moe_engine.buf_q)));
+    std.debug.print("GPU Q projection (first 10 dims):\n  ", .{});
+    for (0..10) |i| std.debug.print("{d:.4} ", .{q_gpu[i]});
+    std.debug.print("\n", .{});
+
+    // 5. Dequantize Q weight to F32 for CPU comparison
+    const q_weight = try allocator.alloc(f32, n_embd * n_embd);
+    defer allocator.free(q_weight);
+    try loader.dequantizeToF32("blk.0.attn_q.weight", q_weight);
+
+    std.debug.print("\nQ weights (first row, first 10): ", .{});
+    for (0..10) |i| std.debug.print("{d:.4} ", .{q_weight[i]});
+    std.debug.print("\n", .{});
+    std.debug.print("Q weights (second row, first 10): ", .{});
+    for (0..10) |i| std.debug.print("{d:.4} ", .{q_weight[n_embd + i]});
+    std.debug.print("\n", .{});
+
+    // 6. Compute Q on CPU (row-major: y[out] = sum_in(W[out*n + in] * x[in]))
+    // GGUF stores [n_out, n_in] in row-major, so W[out, in] = q_weight[out * n_embd + in]
+    const q_cpu = try allocator.alloc(f32, n_embd);
+    defer allocator.free(q_cpu);
+
+    for (0..n_embd) |out_idx| {
+        var sum: f32 = 0;
+        for (0..n_embd) |in_idx| {
+            // Row-major: W[out, in] is at index out * n_embd + in
+            sum += normed[in_idx] * q_weight[out_idx * n_embd + in_idx];
+        }
+        q_cpu[out_idx] = sum;
+    }
+
+    std.debug.print("\nCPU Q projection (first 10 dims):\n  ", .{});
+    for (0..10) |i| std.debug.print("{d:.4} ", .{q_cpu[i]});
+    std.debug.print("\n", .{});
+
+    // Compare
+    var max_diff: f32 = 0;
+    var sum_sq_diff: f32 = 0;
+    for (0..n_embd) |i| {
+        const diff = @abs(q_cpu[i] - q_gpu[i]);
+        if (diff > max_diff) max_diff = diff;
+        sum_sq_diff += diff * diff;
+    }
+    const rms_diff = @sqrt(sum_sq_diff / @as(f32, n_embd));
+
+    std.debug.print("\n=== Comparison ===\n", .{});
+    std.debug.print("Max difference: {d:.6}\n", .{max_diff});
+    std.debug.print("RMS difference: {d:.6}\n", .{rms_diff});
+
+    if (max_diff < 0.05) {
+        std.debug.print("\n✅ PASS: GPU Q4_K matches CPU\n", .{});
+    } else {
+        std.debug.print("\n❌ FAIL: GPU Q4_K differs from CPU!\n", .{});
+
+        // Show some individual diffs
+        std.debug.print("\nFirst 10 differences:\n", .{});
+        for (0..10) |i| {
+            std.debug.print("  [{d}] GPU={d:.4} CPU={d:.4} diff={d:.4}\n", .{i, q_gpu[i], q_cpu[i], @abs(q_gpu[i] - q_cpu[i])});
+        }
+    }
+
+    // ============ K PROJECTION (Q8_0) VERIFICATION ============
+    std.debug.print("\n\n=== K Projection (Q8_0) Verification ===\n", .{});
+
+    const kv_dim: usize = 1024; // n_head_kv * head_dim = 8 * 128
+
+    // Get raw K weight (Q8_0 format)
+    const k_weight_raw = loader.getTensorDataByName("blk.0.attn_k.weight") orelse return error.TensorNotFound;
+    std.debug.print("K weight raw bytes: {} bytes\n", .{k_weight_raw.len});
+
+    // Upload K weights to GPU
+    const k_weight_buf = moe_engine.uploadBuffer(k_weight_raw) orelse return error.BufferUploadFailed;
+    defer objc.release(k_weight_buf);
+
+    // Run GPU Q8_0 matmul (use existing buf_k)
+    std.debug.print("Running GPU Q8_0 matmul...\n", .{});
+    try moe_engine.denseMatVecQ8_0(k_weight_buf, normed_buf, moe_engine.buf_k, @intCast(kv_dim), @intCast(n_embd));
+
+    // Read GPU K result
+    const k_gpu: [*]f32 = @ptrCast(@alignCast(objc.bufferContents(moe_engine.buf_k)));
+    std.debug.print("GPU K projection (first 10 dims):\n  ", .{});
+    for (0..10) |i| std.debug.print("{d:.4} ", .{k_gpu[i]});
+    std.debug.print("\n", .{});
+
+    // Dequantize K weight to F32 for CPU comparison
+    const k_weight_f32 = try allocator.alloc(f32, kv_dim * n_embd);
+    defer allocator.free(k_weight_f32);
+    try loader.dequantizeToF32("blk.0.attn_k.weight", k_weight_f32);
+
+    std.debug.print("K weights (first row, first 10): ", .{});
+    for (0..10) |i| std.debug.print("{d:.4} ", .{k_weight_f32[i]});
+    std.debug.print("\n", .{});
+
+    // Debug: Check first Q8_0 block manually
+    std.debug.print("\nFirst Q8_0 block raw bytes: ", .{});
+    for (0..10) |i| std.debug.print("0x{x:0>2} ", .{k_weight_raw[i]});
+    std.debug.print("\n", .{});
