+    }
+    std.debug.print("\n", .{});
+    std.debug.print("Dequantized first 8 values (manual): ", .{});
+    for (2..10) |i| {
+        const q: i8 = @bitCast(k_weight_raw[i]);
+        const val = first_block_d * @as(f32, @floatFromInt(q));
+        std.debug.print("{d:.4} ", .{val});
