+    std.debug.print("\n", .{});
+
+    // Debug: Check row 0 and row 1 structure
+    std.debug.print("\n--- Row Layout Debug ---\n", .{});
+    const row_stride = 128 * 34; // 128 blocks * 34 bytes each = 4352 bytes per row
+    std.debug.print("Row stride: {} bytes (should be 4352)\n", .{row_stride});
+    std.debug.print("Row 0 starts at byte 0\n", .{});
+    std.debug.print("Row 1 starts at byte {}\n", .{row_stride});
+
+    // Check block 0 of row 1 (should be different from row 0)
+    const row1_block0_d_bits = @as(u16, k_weight_raw[row_stride]) | (@as(u16, k_weight_raw[row_stride + 1]) << 8);
+    const row1_block0_d_f16: f16 = @bitCast(row1_block0_d_bits);
+    const row1_block0_d: f32 = @floatCast(row1_block0_d_f16);
+    std.debug.print("Row 1 block 0 d: {d:.6} (should differ from row 0: {d:.6})\n", .{ row1_block0_d, first_block_d });
+
+    // Manual CPU computation for first output only, showing each block contribution
+    std.debug.print("\n--- Manual CPU K[0] computation ---\n", .{});
+    var manual_sum: f32 = 0;
+    var block_contributions: [4]f32 = undefined;
+    for (0..4) |blk_idx| {
