+//! Test Q4_K scale values to check for sign flips
+
+const std = @import("std");
+const gguf_loader = @import("inference/gguf_loader.zig");
+
+pub fn main() !void {
+    var gpa = std.heap.GeneralPurposeAllocator(.{}){};
+    defer _ = gpa.deinit();
+    const allocator = gpa.allocator();
+
+    const args = try std.process.argsAlloc(allocator);
+    defer std.process.argsFree(allocator, args);
+
+    if (args.len < 2) {
+        std.debug.print("Usage: {s} <model.gguf>\n", .{args[0]});
+        return error.MissingArgument;
+    }
+
+    const model_path = args[1];
+
+    // Load GGUF
+    std.debug.print("Loading GGUF file: {s}\n", .{model_path});
+    var loader = try gguf_loader.GGUFLoader.init(allocator, model_path);
+    defer loader.deinit();
+
+    // Get Q weight tensor info
+    const q_tensor = loader.getTensor("blk.0.attn_q.weight") orelse return error.TensorNotFound;
+    const q_data = loader.getTensorData(q_tensor);
+
+    std.debug.print("\n=== Q4_K Block Structure Analysis ===\n", .{});
+    std.debug.print("Tensor type: {s}\n", .{@tagName(q_tensor.type_)});
+    std.debug.print("Tensor size: {} bytes\n", .{q_data.len});
+
+    // Q4_K block is 144 bytes (2 + 2 + 12 + 128)
+    const Q4_K_BLOCK_SIZE = 144;
+    const num_blocks = q_data.len / Q4_K_BLOCK_SIZE;
+    std.debug.print("Number of Q4_K blocks: {}\n", .{num_blocks});
+
+    // Examine first few blocks
+    std.debug.print("\nFirst 10 blocks:\n", .{});
+    for (0..@min(10, num_blocks)) |i| {
+        const block_offset = i * Q4_K_BLOCK_SIZE;
+        const block_data = q_data[block_offset..][0..Q4_K_BLOCK_SIZE];
+
+        // Read d (f16 at offset 0)
+        const d_u16: u16 = @as(*const u16, @ptrCast(@alignCast(block_data.ptr))).*;
+        const d_f32 = f16ToF32(d_u16);
+
+        // Read dmin (f16 at offset 2)
+        const dmin_u16: u16 = @as(*const u16, @ptrCast(@alignCast(block_data.ptr + 2))).*;
+        const dmin_f32 = f16ToF32(dmin_u16);
+
+        std.debug.print("  Block {}: d={d:.6}, dmin={d:.6}", .{ i, d_f32, dmin_f32 });
+
+        // Check for negative values
+        if (d_f32 < 0 or dmin_f32 < 0) {
+            std.debug.print(" ⚠️  NEGATIVE SCALE!", .{});
+        }
+        std.debug.print("\n", .{});
+    }
+
+    // Statistics
+    var d_positive: usize = 0;
+    var d_negative: usize = 0;
+    var dmin_positive: usize = 0;
+    var dmin_negative: usize = 0;
+    var d_sum: f32 = 0;
+    var dmin_sum: f32 = 0;
+
+    for (0..num_blocks) |i| {
+        const block_offset = i * Q4_K_BLOCK_SIZE;
+        const block_data = q_data[block_offset..][0..Q4_K_BLOCK_SIZE];
+
+        const d_u16: u16 = @as(*const u16, @ptrCast(@alignCast(block_data.ptr))).*;
+        const d_f32 = f16ToF32(d_u16);
+
+        const dmin_u16: u16 = @as(*const u16, @ptrCast(@alignCast(block_data.ptr + 2))).*;
+        const dmin_f32 = f16ToF32(dmin_u16);
+
+        d_sum += d_f32;
+        dmin_sum += dmin_f32;
+
+        if (d_f32 > 0) d_positive += 1;
+        if (d_f32 < 0) d_negative += 1;
+        if (dmin_f32 > 0) dmin_positive += 1;
+        if (dmin_f32 < 0) dmin_negative += 1;
+    }
+
+    std.debug.print("\n=== Scale Statistics ===\n", .{});
+    std.debug.print("d (super-block scale):\n", .{});
+    std.debug.print("  Positive: {} ({d:.1}%)\n", .{ d_positive, 100.0 * @as(f32, @floatFromInt(d_positive)) / @as(f32, @floatFromInt(num_blocks)) });
+    std.debug.print("  Negative: {} ({d:.1}%)\n", .{ d_negative, 100.0 * @as(f32, @floatFromInt(d_negative)) / @as(f32, @floatFromInt(num_blocks)) });
+    std.debug.print("  Mean: {d:.8}\n", .{d_sum / @as(f32, @floatFromInt(num_blocks))});
+
+    std.debug.print("\ndmin (super-block min scale):\n", .{});
+    std.debug.print("  Positive: {} ({d:.1}%)\n", .{ dmin_positive, 100.0 * @as(f32, @floatFromInt(dmin_positive)) / @as(f32, @floatFromInt(num_blocks)) });
+    std.debug.print("  Negative: {} ({d:.1}%)\n", .{ dmin_negative, 100.0 * @as(f32, @floatFromInt(dmin_negative)) / @as(f32, @floatFromInt(num_blocks)) });
+    std.debug.print("  Mean: {d:.8}\n", .{dmin_sum / @as(f32, @floatFromInt(num_blocks))});
+
+    if (d_negative > 0 or dmin_negative > 0) {
+        std.debug.print("\n❌ FOUND NEGATIVE SCALES! This would flip the sign of weights!\n", .{});
+    } else {
+        std.debug.print("\n✅ All scales are positive (as expected for Q4_K)\n", .{});
+    }
+}
+
+fn f16ToF32(h: u16) f32 {
+    const f16_val: f16 = @bitCast(h);
+    return @floatCast(f16_val);
+}

