+//! Minimal test for Q8_0 kernel correctness
+//! Tests the dense_mvm_q8_0 Metal kernel with synthetic data
+
+const std = @import("std");
+const moe_metal = @import("moe_metal.zig");
+const objc = @import("inference/metal/objc.zig");
+const gguf_loader = @import("inference/gguf_loader.zig");
+
+pub fn main() !void {
+    var gpa = std.heap.GeneralPurposeAllocator(.{}){};
+    defer _ = gpa.deinit();
+    const allocator = gpa.allocator();
+
+    const args = try std.process.argsAlloc(allocator);
+    defer std.process.argsFree(allocator, args);
+
+    std.debug.print("\n=== Q8_0 KERNEL TEST ===\n\n", .{});
+
+    // Initialize Metal
+    var engine = try moe_metal.MetalMoEEngine.init(allocator);
+    defer engine.deinit();
+
+    // Test dimensions: small matrix for easy verification
+    const n_out: u32 = 4;   // 4 output rows
+    const n_in: u32 = 128;  // 128 input elements (4 blocks of 32)
+    const blocks_per_row = (n_in + 31) / 32;  // = 4 blocks
+    const Q8_BLOCK_BYTES: u32 = 34;           // 2 byte scale + 32 int8
+    const row_bytes = blocks_per_row * Q8_BLOCK_BYTES;  // = 136 bytes per row
+    const total_weight_bytes = n_out * row_bytes;       // = 544 bytes
+
+    std.debug.print("Test config: n_out={}, n_in={}, blocks_per_row={}\n", .{n_out, n_in, blocks_per_row});
+    std.debug.print("Weight bytes: {} per row, {} total\n\n", .{row_bytes, total_weight_bytes});
+
+    // Create synthetic Q8_0 weights
+    // Each block: 2 bytes f16 scale + 32 int8 values
+    var weights = try allocator.alloc(u8, total_weight_bytes);
+    defer allocator.free(weights);
+
+    // Fill with known pattern:
+    // - Scale = 1.0 (f16 = 0x3C00)
+    // - All int8 values = 1
+    // This means each block contributes: 1.0 * sum(input[block]) = sum(input[block])
+    for (0..n_out) |row| {
+        for (0..blocks_per_row) |blk| {
+            const offset = row * row_bytes + blk * Q8_BLOCK_BYTES;
+            // f16 1.0 = 0x3C00 (little endian: 0x00, 0x3C)
+            weights[offset] = 0x00;
+            weights[offset + 1] = 0x3C;
+            // All int8 values = 1
+            for (0..32) |i| {
+                weights[offset + 2 + i] = 1;
+            }
+        }
+    }
+
+    // Verify first block
+    const scale_u16 = @as(u16, weights[0]) | (@as(u16, weights[1]) << 8);
+    const scale_f16: f16 = @bitCast(scale_u16);
+    std.debug.print("First block scale: u16=0x{X:0>4}, f16={d:.4}, f32={d:.4}\n", .{
+        scale_u16, scale_f16, @as(f32, @floatCast(scale_f16))
+    });
+
+    // Create input vector: all 1.0
+    var input: [128]f32 = undefined;
+    for (0..128) |i| {
+        input[i] = 1.0;
+    }
+
+    // Expected output: each row = sum(scale * sum(int8 * input))
+    // With scale=1.0, int8=1, input=1.0:
+    // Each block contributes: 1.0 * (32 * 1.0) = 32.0
+    // Each row has 4 blocks: 4 * 32.0 = 128.0
+    const expected_output: f32 = 128.0;
+    std.debug.print("Expected output per row: {d:.1}\n\n", .{expected_output});
+
+    // Upload weights to GPU
+    const weight_buf = objc.deviceNewBufferWithBytes(
+        engine.device,
+        weights.ptr,
+        total_weight_bytes,
+        objc.MTLResourceStorageModeShared
+    ) orelse return error.BufferCreationFailed;
+    defer objc.release(weight_buf);
+
+    // Upload input to buf_normed (reusing existing buffer)
+    engine.uploadToBuffer(engine.buf_normed, &input);
+
+    // Create output buffer
+    const output_buf = objc.deviceNewBuffer(
+        engine.device,
+        n_out * @sizeOf(f32),
+        objc.MTLResourceStorageModeShared
+    ) orelse return error.BufferCreationFailed;
+    defer objc.release(output_buf);
+
+    // Run Q8_0 kernel
+    std.debug.print("Running dense_mvm_q8_0 kernel...\n", .{});
+    try engine.denseMatVecQ8_0(weight_buf, engine.buf_normed, output_buf, n_out, n_in);
+
+    // Read back results
+    const output_ptr: [*]f32 = @ptrCast(@alignCast(objc.bufferContents(output_buf)));
+
+    std.debug.print("\nResults:\n", .{});
+    var all_correct = true;
+    for (0..n_out) |i| {
+        const actual = output_ptr[i];
+        const error_pct = @abs(actual - expected_output) / expected_output * 100.0;
+        const status = if (error_pct < 1.0) "✓" else "✗";
+        std.debug.print("  Row {}: expected={d:.1}, actual={d:.4}, error={d:.2}% {s}\n", .{
+            i, expected_output, actual, error_pct, status
+        });
+        if (error_pct >= 1.0) all_correct = false;
+    }
+
+    std.debug.print("\n", .{});
+    if (all_correct) {
+        std.debug.print("=== TEST PASSED ===\n", .{});
+    } else {
+        std.debug.print("=== TEST FAILED ===\n", .{});
+    }
+
+    // Now test with smaller scale (like V weights have)
+    std.debug.print("\n=== SMALL SCALE TEST ===\n", .{});
+
+    // Scale = 0.0001 (very small, like V weights)
+    // f16 0.0001 ≈ 0x17B7 = 0.0001001...
+    const small_scale: f16 = 0.0001;
+    const small_scale_u16: u16 = @bitCast(small_scale);
+    std.debug.print("Small scale: f16={d:.6}, u16=0x{X:0>4}\n", .{small_scale, small_scale_u16});
+
+    // Update weights with small scale
+    for (0..n_out) |row| {
+        for (0..blocks_per_row) |blk| {
+            const offset = row * row_bytes + blk * Q8_BLOCK_BYTES;
+            weights[offset] = @truncate(small_scale_u16 & 0xFF);
+            weights[offset + 1] = @truncate((small_scale_u16 >> 8) & 0xFF);
+        }
+    }
+
+    // Re-upload weights
+    const weight_buf2 = objc.deviceNewBufferWithBytes(
+        engine.device,
+        weights.ptr,
+        total_weight_bytes,
+        objc.MTLResourceStorageModeShared
+    ) orelse return error.BufferCreationFailed;
+    defer objc.release(weight_buf2);
+
+    // Expected: 0.0001 * 32 * 4 blocks = 0.0128
