+    std.debug.print("Expected output with small scale: {d:.6}\n", .{expected_small});
+
+    // Run kernel
+    try engine.denseMatVecQ8_0(weight_buf2, engine.buf_normed, output_buf, n_out, n_in);
+
+    // Check results
+    std.debug.print("\nSmall scale results:\n", .{});
+    for (0..n_out) |i| {
+        const actual = output_ptr[i];
+        const error_pct = if (expected_small > 0) @abs(actual - expected_small) / expected_small * 100.0 else 0;
+        const status = if (error_pct < 1.0) "✓" else "✗";
+        std.debug.print("  Row {}: expected={d:.6}, actual={d:.6}, error={d:.2}% {s}\n", .{
+            i, expected_small, actual, error_pct, status
+        });
+    }
+
+    // ===========================================
+    // TEST WITH ACTUAL MODEL WEIGHTS
+    // ===========================================
+    if (args.len < 2) {
+        std.debug.print("\n(Skipping model weight test - no model path provided)\n", .{});
+        return;
+    }
+
+    const model_path = args[1];
+    std.debug.print("\n=== ACTUAL MODEL WEIGHT TEST ===\n", .{});
+    std.debug.print("Loading model: {s}\n\n", .{model_path});
+
+    var loader = try gguf_loader.GGUFLoader.init(allocator, model_path);
+    defer loader.deinit();
+
+    // Get K and V weights for layer 0
+    const attn_k = loader.getTensorDataByName("blk.0.attn_k.weight") orelse {
+        std.debug.print("ERROR: Could not find K weights\n", .{});
+        return;
+    };
+    const attn_v = loader.getTensorDataByName("blk.0.attn_v.weight") orelse {
+        std.debug.print("ERROR: Could not find V weights\n", .{});
+        return;
+    };
+
+    std.debug.print("K weights: {} bytes\n", .{attn_k.len});
+    std.debug.print("V weights: {} bytes\n", .{attn_v.len});
+
+    // Model dimensions
+    const model_n_embd: u32 = 4096;
+    const model_kv_dim: u32 = 1024;  // 8 heads * 128 dim
+
+    // Create input buffer with all 1.0
+    var model_input: [4096]f32 = undefined;
+    for (0..4096) |i| {
+        model_input[i] = 1.0;
+    }
+    engine.uploadToBuffer(engine.buf_normed, &model_input);
+
+    // Upload K and V weights
+    const k_buf = objc.deviceNewBufferWithBytes(
+        engine.device,
+        attn_k.ptr,
+        attn_k.len,
+        objc.MTLResourceStorageModeShared
+    ) orelse return error.BufferCreationFailed;
+    defer objc.release(k_buf);
+
+    const v_buf = objc.deviceNewBufferWithBytes(
+        engine.device,
+        attn_v.ptr,
+        attn_v.len,
+        objc.MTLResourceStorageModeShared
+    ) orelse return error.BufferCreationFailed;
+    defer objc.release(v_buf);
+
+    // Create output buffers
+    const k_out_buf = objc.deviceNewBuffer(
+        engine.device,
+        model_kv_dim * @sizeOf(f32),
+        objc.MTLResourceStorageModeShared
+    ) orelse return error.BufferCreationFailed;
+    defer objc.release(k_out_buf);
+
+    const v_out_buf = objc.deviceNewBuffer(
+        engine.device,
+        model_kv_dim * @sizeOf(f32),
+        objc.MTLResourceStorageModeShared
