+    defer objc.release(v_out_buf);
+
+    // Run K projection
+    std.debug.print("\nRunning K projection...\n", .{});
+    try engine.denseMatVecQ8_0(k_buf, engine.buf_normed, k_out_buf, model_kv_dim, model_n_embd);
