+    const Q8_BLOCK = 34;
+    const blocks_per_row_model = (model_n_embd + 31) / 32;  // 128 blocks
+
+    var cpu_k0: f64 = 0;
+    var cpu_v0: f64 = 0;
+    for (0..blocks_per_row_model) |blk| {
+        const blk_off = blk * Q8_BLOCK;
+
+        // K
+        const k_scale_u16 = @as(u16, attn_k[blk_off]) | (@as(u16, attn_k[blk_off + 1]) << 8);
+        const k_scale: f64 = @floatCast(@as(f16, @bitCast(k_scale_u16)));
