+
+    const k_ratio = cpu_k0 / @as(f64, k_out_ptr[0]);
+    const v_ratio = cpu_v0 / @as(f64, v_out_ptr[0]);
+    std.debug.print("  K CPU/GPU ratio: {d:.2}x\n", .{k_ratio});
+    std.debug.print("  V CPU/GPU ratio: {d:.2}x\n", .{v_ratio});
+
+    if (@abs(k_ratio - 1.0) < 0.1 and @abs(v_ratio - 1.0) < 0.1) {
+        std.debug.print("\n=== MODEL WEIGHT TEST PASSED ===\n", .{});
+    } else {
+        std.debug.print("\n=== MODEL WEIGHT TEST FAILED ===\n", .{});
+        std.debug.print("Expected CPU/GPU ratio ~1.0 for both K and V\n", .{});
+    }
+}

