+//! Test Q/K weight permutation hypothesis
+//! Check if GGUF weights are stored in a permuted layout
+
+const std = @import("std");
+const gguf_loader = @import("inference/gguf_loader.zig");
+
+pub fn main() !void {
+    var gpa = std.heap.GeneralPurposeAllocator(.{}){};
+    defer _ = gpa.deinit();
+    const allocator = gpa.allocator();
+
+    const args = try std.process.argsAlloc(allocator);
+    defer std.process.argsFree(allocator, args);
+
+    if (args.len < 2) {
+        std.debug.print("Usage: {s} <model.gguf>\n", .{args[0]});
+        return error.MissingArgument;
+    }
+
+    const model_path = args[1];
+
+    // Load GGUF
+    std.debug.print("Loading GGUF file: {s}\n", .{model_path});
+    var loader = try gguf_loader.GGUFLoader.init(allocator, model_path);
+    defer loader.deinit();
+
+    // Get Q and K weights for layer 0
+    const attn_q_info = loader.getTensor("blk.0.attn_q.weight") orelse return error.TensorNotFound;
+    const attn_k_info = loader.getTensor("blk.0.attn_k.weight") orelse return error.TensorNotFound;
+
+    std.debug.print("\n=== Layer 0 Attention Weights ===\n", .{});
+    std.debug.print("Q weight: type={s}, dims={any}, elements={}\n", .{
+        @tagName(attn_q_info.type_),
+        attn_q_info.dimensions[0..attn_q_info.n_dims],
+        attn_q_info.numElements(),
+    });
+    std.debug.print("K weight: type={s}, dims={any}, elements={}\n", .{
+        @tagName(attn_k_info.type_),
+        attn_k_info.dimensions[0..attn_k_info.n_dims],
+        attn_k_info.numElements(),
+    });
+
+    // Dequantize a small portion of Q weights to examine layout
+    // For Mixtral: n_head=32, head_dim=128, n_embd=4096
+    // Q shape should be [n_embd, n_embd] = [4096, 4096]
+    // We want to look at the first row (output dim 0) which should correspond to head 0, dimension 0
+
+    const sample_size = 256; // First 256 elements
+    const q_sample = try allocator.alloc(f32, sample_size);
+    defer allocator.free(q_sample);
+
+    // Dequantize first 256 elements
+    std.debug.print("\nDequantizing first {} elements of Q weight...\n", .{sample_size});
+    try loader.dequantizePartialQ4K(attn_q_info, q_sample, 0, sample_size);
+
+    std.debug.print("\n=== Q Weight Layout Analysis ===\n", .{});
+    std.debug.print("First row (output dim 0) samples:\n", .{});
+    std.debug.print("  q[0..10]: {any}\n", .{q_sample[0..10]});
+    std.debug.print("  q[64..74]: {any}\n", .{q_sample[64..74]});
+    std.debug.print("  q[128..138]: {any}\n", .{q_sample[128..138]});
+
+    // Check for permutation pattern
+    // If permuted as [0, 64, 1, 65, 2, 66, ...], then:
+    // - Even indices should be from first half
+    // - Odd indices should be from second half
+    std.debug.print("\n=== Checking for Permutation Pattern ===\n", .{});
+    std.debug.print("Expecting normal layout: [0, 1, 2, 3, ...]\n", .{});
+    std.debug.print("If permuted: [0, 64, 1, 65, 2, 66, ...]\n", .{});
+    std.debug.print("\nPattern check (every other value):\n", .{});
+    std.debug.print("  Even indices [0, 2, 4, 6, 8]: {d:.4} {d:.4} {d:.4} {d:.4} {d:.4}\n", .{
+        q_sample[0], q_sample[2], q_sample[4], q_sample[6], q_sample[8],
+    });
+    std.debug.print("  Odd indices  [1, 3, 5, 7, 9]: {d:.4} {d:.4} {d:.4} {d:.4} {d:.4}\n", .{
+        q_sample[1], q_sample[3], q_sample[5], q_sample[7], q_sample[9],
+    });
+
+    // Compute variance within even/odd groups
+    var even_mean: f32 = 0;
+    var odd_mean: f32 = 0;
+    for (0..64) |i| {
+        if (i % 2 == 0) {
+            even_mean += q_sample[i];
+        } else {
+            odd_mean += q_sample[i];
+        }
+    }
+    even_mean /= 32;
+    odd_mean /= 32;
+
+    var even_var: f32 = 0;
+    var odd_var: f32 = 0;
+    for (0..64) |i| {
+        if (i % 2 == 0) {
+            const diff = q_sample[i] - even_mean;
+            even_var += diff * diff;
+        } else {
+            const diff = q_sample[i] - odd_mean;
+            odd_var += diff * diff;
+        }
+    }
+    even_var /= 32;
+    odd_var /= 32;
+
+    std.debug.print("\nStatistics (first 64 elements):\n", .{});
+    std.debug.print("  Even indices: mean={d:.4}, variance={d:.4}\n", .{ even_mean, even_var });
+    std.debug.print("  Odd indices:  mean={d:.4}, variance={d:.4}\n", .{ odd_mean, odd_var });
+
+    // If permuted, even and odd groups would come from different parts of the original vector
+    // and likely have different statistics
+    const ratio = if (even_var > odd_var) even_var / odd_var else odd_var / even_var;
+    if (ratio > 2.0) {
+        std.debug.print("\n⚠️  Large variance ratio ({d:.2}) suggests PERMUTED layout!\n", .{ratio});
+    } else {
+        std.debug.print("\n✅ Similar variance suggests NORMAL (non-permuted) layout\n", .{});
+    }
+}

